INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('36fb04ed-77fb-57d2-bb7a-8d69eb7353c6', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'accept', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ækˈsɛpt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/accept-uk.mp3', 'To receive, especially with a consent, with favour, or with approval.', 'The Boy Scouts were going to accept him as a member.', 'Emotions & Feelings', 'chấp nhận', 'Nhận, đặc biệt là với sự đồng ý, với thiện cảm, hoặc với sự chấp thuận.', 'Hướng đạo sinh sắp chấp nhận cậu ấy làm thành viên.'),
    ('9e419304-d4a9-5a59-add1-6c8e72cbcc52', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'affect', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/əˈfɛkt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/affect-1-au.mp3', 'To influence or alter.', 'The experience affected me deeply.', 'Emotions & Feelings', 'ảnh hưởng, tác động', 'Gây ảnh hưởng hoặc thay đổi.', 'Trải nghiệm đó ảnh hưởng sâu sắc đến tôi.'),
    ('d9ed6d81-36cc-5d80-a6dd-4034bc1424e8', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'alone', 'A2', '["adj", "adv"]'::jsonb, '[{"pos": "adj", "level": "A2"}, {"pos": "adv", "level": "A2"}]'::jsonb, '/əˈləʊn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/alone-uk.mp3', 'By oneself, solitary.', 'I can''t ask for help because I am alone.', 'Emotions & Feelings', 'một mình', 'Một mình, cô đơn.', 'Tôi không thể nhờ giúp đỡ vì tôi chỉ có một mình.'),
    ('e1895f89-9b1d-507c-9a07-aa8443fa7a44', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'avoid', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/əˈvɔɪd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/avoid-us.mp3', 'To try not to meet or communicate with (a person); to shun', 'I try to avoid the company of gamblers.', 'Emotions & Feelings', 'tránh', 'Cố gắng không gặp gỡ hoặc giao tiếp với (một người); xa lánh.', 'Tôi cố gắng tránh xa những tay cờ bạc.'),
    ('37ba35e1-1d89-5837-91c5-0f5d7e62d21b', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'awful', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈɔːfəl/', 'audio/awful.mp3', 'Very bad.', 'My socks smell awful.', 'Emotions & Feelings', 'kinh khủng, tồi tệ', 'Rất tệ.', 'Tất của tôi có mùi kinh khủng.'),
    ('2dc180c9-edef-56a2-bf90-e4a1776acf95', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'behave', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/bəˈheɪv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/behave-us.mp3', 'To conduct (oneself) well, or in a given way.', 'You need to behave yourself, young lady.', 'Emotions & Feelings', 'cư xử', 'Cư xử (bản thân) tốt, hoặc theo một cách nhất định.', 'Con cần phải cư xử đúng mực, cô gái trẻ.'),
    ('4dd7d200-fb84-5934-bc41-e1add84de899', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'behaviour', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/bɪˈheɪvjə/', 'audio/behaviour.mp3', 'The way a living creature behaves or acts.', 'She can''t stop the strange behaviour because she has OCD (obsessive-compulsive disorder).', 'Emotions & Feelings', 'hành vi', 'Cách một sinh vật sống cư xử hoặc hành động.', 'Cô ấy không thể ngừng hành vi kỳ lạ vì cô ấy mắc chứng OCD (rối loạn ám ảnh cưỡng chế).'),
    ('4c6a2cd2-c1d3-5ef6-bcb9-5cc45920e47f', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'care', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/kɛə/', 'audio/care.mp3', 'Grief, sorrow.', 'Care should be taken when holding babies.', 'Emotions & Feelings', 'quan tâm, chăm sóc', 'Nỗi buồn, sự đau khổ.', 'Nên cẩn thận khi bế trẻ sơ sinh.'),
    ('801f3537-1375-5377-a701-a7636a0ecba1', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'complain', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/kəmˈpleɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/complain-us.mp3', 'To express feelings of pain, dissatisfaction, or resentment.', 'Joe was always complaining about the noise made by his neighbours.', 'Emotions & Feelings', 'phàn nàn', 'Bày tỏ cảm giác đau đớn, bất mãn hoặc bực bội.', 'Joe luôn phàn nàn về tiếng ồn do hàng xóm của anh ấy gây ra.'),
    ('e606a4ff-2770-5f41-96ed-c4028a1ee5ed', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'crazy', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈkɹeɪzi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/crazy-us.mp3', 'An insane or eccentric person; a crackpot.', 'His ideas were both frightening and crazy.', 'Emotions & Feelings', 'điên rồ', 'Một người mất trí hoặc lập dị; một người gàn dở.', 'Ý tưởng của anh ta vừa đáng sợ vừa điên rồ.'),
    ('cb6c659e-4aca-563f-a31e-c6c388677eae', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'cry', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/kɹaɪ̯/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cry.mp3', 'A shedding of tears; the act of crying.', 'After we broke up, I retreated to my room for a good cry.', 'Emotions & Feelings', 'khóc', 'Sự rơi nước mắt; hành động khóc.', 'Sau khi chúng tôi chia tay, tôi rút vào phòng để khóc một trận cho thỏa.'),
    ('c09780f5-8f06-5099-b04d-219a21b5476b', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'decision', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/dɪˈsɪʒən/', 'audio/decision.mp3', 'The act of deciding.', 'It is the decision of the court that movies are protected as free speech.', 'Emotions & Feelings', 'quyết định', 'Hành động quyết định.', 'Đó là quyết định của tòa án rằng phim ảnh được bảo vệ như quyền tự do ngôn luận.'),
    ('8226ab4e-fa3b-5576-add6-639ee944b6cb', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'dream', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/dɹiːm/', 'audio/dream.mp3', 'Imaginary events seen in the mind while sleeping.', 'a dream of bliss', 'Emotions & Feelings', 'giấc mơ', 'Những sự kiện tưởng tượng được nhìn thấy trong tâm trí khi đang ngủ.', 'một giấc mơ hạnh phúc'),
    ('a638fc10-4581-5388-80de-df19ae5f0ac3', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'expect', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ɛkˈspɛkt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/expect-us.mp3', 'To predict or believe that something will happen', 'He never expected to be discovered.', 'Emotions & Feelings', 'mong đợi, dự đoán', 'Dự đoán hoặc tin rằng điều gì đó sẽ xảy ra', 'Anh ấy không bao giờ nghĩ rằng mình sẽ bị phát hiện.'),
    ('1ba1aba9-0191-51e9-88e5-b335594dba38', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'expression', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɪkˈspɹɛʃ.ən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/expression-us.mp3', 'The action of expressing thoughts, ideas, feelings, etc.', 'The expression "break a leg!" should not be taken literally.', 'Emotions & Feelings', 'biểu cảm', 'Hành động biểu đạt suy nghĩ, ý tưởng, cảm xúc, v.v.', 'Thành ngữ "chúc may mắn!" không nên được hiểu theo nghĩa đen.'),
    ('1bcb8a15-a51e-50ca-bb16-44639861e30c', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'fear', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B1"}]'::jsonb, '/fɪə/', 'audio/fear.mp3', 'A strong, uncontrollable, unpleasant emotion or feeling caused by actual or perceived danger or threat.', 'He was struck by fear on seeing the snake.', 'Emotions & Feelings', 'sợ hãi', 'Một cảm xúc hoặc cảm giác mạnh mẽ, không thể kiểm soát, khó chịu gây ra bởi nguy hiểm hoặc mối đe dọa thực tế hoặc được nhận thức.', 'Anh ta sợ hãi khi nhìn thấy con rắn.'),
    ('bd3ea7f4-88ac-53e3-b065-a301c5cb19ec', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'fortunately', 'A2', '["adv"]'::jsonb, '[{"pos": "adv", "level": "A2"}]'::jsonb, '/ˈfɔːt͡ʃənɪtli/', 'audio/fortunately.mp3', 'In a fortunate manner.', 'Fortunately, Sam''s pet hamster was not dead.', 'Emotions & Feelings', 'may mắn thay', 'Theo một cách may mắn.', 'May mắn thay, chuột hamster cưng của Sam không chết.'),
    ('e7d2aaf5-25f8-5e39-9789-011ee06ce6af', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'hurt', 'A2', '["v", "adj", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "adj", "level": "A2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/hɜːt/', 'audio/hurt.mp3', 'An emotional or psychological humiliation or bad experience.', 'how to overcome old hurts of the past', 'Emotions & Feelings', 'tổn thương', 'Một sự sỉ nhục về cảm xúc hoặc tâm lý hoặc một trải nghiệm tồi tệ.', 'làm thế nào để vượt qua những tổn thương cũ trong quá khứ'),
    ('e5f5cdf4-4a05-5f4b-bf56-8eaac04d6ea0', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'incredible', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ɪŋˈkɹɛdɪbəl/', 'audio/incredible.mp3', 'Too implausible to be credible; beyond belief; unbelievable.', 'He was so wrapped up in watching the incredible special effects that he couldn''t keep track of the story.', 'Emotions & Feelings', 'không thể tin được', 'Quá khó tin để có thể tin được; vượt quá niềm tin; không thể tin nổi.', 'Anh ấy quá mải mê xem những hiệu ứng đặc biệt không thể tin được đến nỗi không thể theo dõi câu chuyện.'),
    ('c6a3b059-0739-53f8-be3f-e0639661e9f5', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'laughter', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈlɑːftə/', 'audio/laughter.mp3', 'The sound of laughing, produced by air so expelled; any similar sound.', 'Their loud laughter betrayed their presence.', 'Emotions & Feelings', 'tiếng cười', 'Âm thanh của tiếng cười, được tạo ra bởi không khí được đẩy ra; bất kỳ âm thanh tương tự nào.', 'Tiếng cười lớn của họ đã làm lộ vị trí của họ.'),
    ('3e7db3e6-92b6-5535-abf8-7a992d044c12', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'lazy', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈleɪzi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lazy-us.mp3', 'A lazy person.', 'Get out of bed, you lazy lout!', 'Emotions & Feelings', 'lười biếng', 'Một người lười biếng.', 'Dậy đi, đồ lười biếng!'),
    ('ef3838a6-26bd-55eb-a5e6-c214ee633c03', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'lost', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/lɒst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lost-uk.mp3', 'To cause (something) to cease to be in one''s possession or capability due to unfortunate or unknown circumstances, events or reasons.', 'He lost his hearing in the explosion.', 'Emotions & Feelings', 'bị lạc', 'Làm cho (một thứ gì đó) không còn trong sở hữu hoặc khả năng của một người do những hoàn cảnh, sự kiện hoặc lý do không may hoặc không xác định.', 'Anh ấy bị mất thính lực trong vụ nổ.'),
    ('f6959002-1d72-5987-ab81-ae5c91a49571', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'luck', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/lʊk/', 'audio/luck.mp3', 'Something that happens to someone by chance, a chance occurrence, especially a favourable one.', 'Gilbert had some bad luck yesterday — he got pick-pocketed and lost fifty dollars.', 'Emotions & Feelings', 'vận may', 'Điều gì đó xảy ra với ai đó một cách tình cờ, một sự việc ngẫu nhiên, đặc biệt là một sự việc thuận lợi.', 'Gilbert đã gặp một chút xui xẻo ngày hôm qua — anh ấy bị móc túi và mất năm mươi đô la.'),
    ('5c8a1099-ba9b-5f59-bfc9-6ee138a6609b', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'lucky', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈlʌki/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lucky-us.mp3', '(of people) Favoured by luck; fortunate; having good success or good fortune', 'The downed pilot is very lucky to be alive.', 'Emotions & Feelings', 'may mắn', '(của con người) Được may mắn ưu ái; có phước; có thành công hoặc vận may tốt', 'Phi công bị bắn hạ rất may mắn khi còn sống.'),
    ('6d175e8d-9819-51ee-9399-2436c2a2333b', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'missing', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈmɪsɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/missing-us.mp3', 'To fail to hit.', 'I missed the target.', 'Emotions & Feelings', 'thiếu, mất tích', 'Không đánh trúng.', 'Tôi đã bắn trượt mục tiêu.'),
    ('d6a53a80-0b60-5533-9afa-a5a6e2667f41', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'personality', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/-i/', 'https://api.dictionaryapi.dev/media/pronunciations/en/personality-uk.mp3', 'A set of non-physical psychological and social qualities that make a person (or thing) distinct from another.', 'The president has a unique personality.', 'Emotions & Feelings', 'tính cách, nhân cách', 'Một tập hợp các phẩm chất tâm lý và xã hội phi vật thể làm cho một người (hoặc vật) khác biệt với người khác.', 'Tổng thống có một tính cách độc đáo.'),
    ('d7cdc437-d3d8-569d-8a6e-7951275bf05c', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'pleased', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/pliːzd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pleased-us.mp3', 'To make happy or satisfy; to give pleasure to.', 'Her presentation pleased the executives.', 'Emotions & Feelings', 'hài lòng', 'Làm cho hạnh phúc hoặc thỏa mãn; mang lại niềm vui cho.', 'Bài thuyết trình của cô ấy làm hài lòng các giám đốc điều hành.'),
    ('2e17e519-2220-577e-b117-8ce11508f0d4', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'promise', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "A2"}]'::jsonb, '/ˈpɹɒmɪs/', 'audio/promise.mp3', 'An oath or affirmation; a vow', 'if I make a promise, I always stick to it; he broke his promise', 'Emotions & Feelings', 'lời hứa', 'Một lời thề hoặc khẳng định; một lời thề', 'nếu tôi hứa, tôi luôn giữ lời; anh ấy đã thất hứa'),
    ('0cbc29ab-745e-5de9-844b-6423c9c9db14', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'realize', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ˈɹɪə.laɪz/', 'audio/realize.mp3', 'To make real; to convert from the imaginary or fictitious into reality; to bring into real existence', 'The objectives of the project were never fully realized.', 'Emotions & Feelings', 'nhận ra', 'Làm cho thành thực; chuyển từ tưởng tượng hoặc hư cấu thành hiện thực; mang vào sự tồn tại thực.', 'Các mục tiêu của dự án không bao giờ được thực hiện đầy đủ.'),
    ('c079c86e-4ac7-5977-acb7-ef2efda2020e', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'recognize', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ˈɹɛkənaɪz/', 'https://api.dictionaryapi.dev/media/pronunciations/en/recognize-uk.mp3', 'To match (something or someone which one currently perceives) to a memory of some previous encounter with the same person or thing.', 'I recognised his face immediately.', 'Emotions & Feelings', 'nhận ra', 'Khớp (một cái gì đó hoặc ai đó mà người ta hiện đang nhận thấy) với ký ức về một lần gặp trước đó với cùng người hoặc vật đó.', 'Tôi nhận ra khuôn mặt của anh ấy ngay lập tức.'),
    ('ff2ca78c-153d-5d58-bc62-a45eb0f38577', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'rude', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ɹʉːd/', 'audio/rude.mp3', 'Bad-mannered.', 'Karen broke up with Fred because he was often rude to her.', 'Emotions & Feelings', 'thô lỗ', 'Thái độ xấu.', 'Karen chia tay Fred vì anh ta thường thô lỗ với cô.'),
    ('098c3173-3ee5-5963-be3c-82f2d442015a', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'sadly', 'A2', '["adv"]'::jsonb, '[{"pos": "adv", "level": "A2"}]'::jsonb, '/ˈsadli/', 'audio/sadly.mp3', 'In a sad manner; sorrowfully.', '“Only when we climb up can we see it,” he said sadly.', 'Emotions & Feelings', 'một cách buồn bã', 'Một cách buồn bã; đầy sầu muộn.', '“Chỉ khi chúng ta leo lên cao mới có thể nhìn thấy nó,” anh ấy nói một cách buồn bã.'),
    ('ce7696a7-fbdc-50c9-9093-c8a055c6aa15', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'scared', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/skɛəd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/scared-uk.mp3', 'To frighten, terrify, startle, especially in a minor way.', 'Did it scare you when I said "Boo!"?', 'Emotions & Feelings', 'sợ hãi', 'Làm sợ hãi, kinh hãi, giật mình, đặc biệt theo cách nhẹ.', 'Nó có làm bạn sợ khi tôi nói ''Boo!'' không?'),
    ('e8246c95-6f0b-5894-87b3-5797e5555b1b', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'scary', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈskɛəɹi/', 'audio/scary.mp3', 'Causing or able to cause fright.', 'She was hiding behind her pillow during the scary parts of the film.', 'Emotions & Feelings', 'đáng sợ', 'Gây ra hoặc có khả năng gây ra sự sợ hãi.', 'Cô ấy đã trốn sau gối trong những phần đáng sợ của bộ phim.'),
    ('ccf90460-c67d-5d4f-9b5d-57c6b0abd13b', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'serious', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈsɪə.ɹi.əs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/serious-uk.mp3', 'Without humor or expression of happiness; grave in manner or disposition', 'It was a surprise to see the captain, who had always seemed so serious, laugh so heartily.', 'Emotions & Feelings', 'nghiêm túc', 'Không có sự hài hước hoặc biểu hiện của hạnh phúc; nghiêm trang trong cách cư xử hoặc tính cách.', 'Thật là bất ngờ khi thấy đội trưởng, người luôn có vẻ rất nghiêm túc, lại cười vui vẻ đến vậy.'),
    ('78f97940-4550-5891-a5b5-5ef84722d9f5', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'smile', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "A2"}]'::jsonb, '/ˈsmaɪ.əl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/smile-us.mp3', 'A facial expression comprised by flexing the muscles of both ends of one''s mouth, often showing the front teeth, without vocalisation, and in humans is a common involuntary or voluntary expression of happiness, pleasure, amusement or anxiety.', 'He always puts a smile on my face.', 'Emotions & Feelings', 'cười/nụ cười', 'Một biểu hiện trên khuôn mặt được tạo thành bởi việc co cơ ở cả hai đầu miệng, thường để lộ răng trước, không phát ra tiếng, và ở con người là một biểu hiện phổ biến không tự chủ hoặc tự chủ của', 'Anh ấy luôn làm tôi mỉm cười.'),
    ('36bff02f-551f-5117-bc43-5547b4796ca2', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'strange', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈstɹeɪnd͡ʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/strange-us.mp3', 'Vagina', 'He thought it strange that his girlfriend wore shorts in the winter.', 'Emotions & Feelings', 'kỳ lạ', 'Âm đạo', 'Anh ấy thấy lạ khi bạn gái mình mặc quần đùi vào mùa đông.'),
    ('fc9f2088-ae64-52bb-857f-6d10f764dcdf', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'stupid', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈstjuːpɪd/', 'audio/stupid.mp3', 'A stupid person; a fool.', 'His stupid knows no bounds.', 'Emotions & Feelings', 'ngu ngốc', 'Một người ngu ngốc; một kẻ ngốc.', 'Sự ngu ngốc của hắn không có giới hạn.'),
    ('87775146-1a05-5778-8ff4-fc8612288d25', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'suddenly', 'A2', '["adv"]'::jsonb, '[{"pos": "adv", "level": "A2"}]'::jsonb, '/ˈsʌdn̩li/', 'https://api.dictionaryapi.dev/media/pronunciations/en/suddenly-us.mp3', 'Happening quickly and with little or no warning; in a sudden manner.', 'Suddenly, the heavens opened and we all got drenched.', 'Emotions & Feelings', 'một cách đột ngột', 'Xảy ra nhanh chóng và với ít hoặc không có cảnh báo; một cách bất ngờ.', 'Đột nhiên, trời đổ mưa và tất cả chúng tôi đều bị ướt sũng.'),
    ('c304c830-973a-5792-bd9a-eb086f6e2af1', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'surprise', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/səˈpɹaɪz/', 'audio/surprise.mp3', 'Something unexpected.', 'It was a surprise to find out I owed twice as much as I thought I did.', 'Emotions & Feelings', 'sự ngạc nhiên', 'Điều gì đó bất ngờ.', 'Thật là một bất ngờ khi phát hiện ra tôi nợ gấp đôi số tôi nghĩ.'),
    ('921acd48-8b96-5e2e-993d-7f020924033f', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'surprised', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/səˈpɹaɪzd/', 'audio/surprised.mp3', 'To cause (someone) to feel unusually alarmed or delighted by something unexpected.', 'It surprises me that I owe twice as much as I thought I did.', 'Emotions & Feelings', 'ngạc nhiên', 'Khiến (ai đó) cảm thấy báo động hoặc vui mừng một cách khác thường bởi điều gì đó bất ngờ.', 'Tôi ngạc nhiên khi biết mình nợ gấp đôi số tôi nghĩ.'),
    ('611cee96-04ca-520e-aae2-d726d99f2e22', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'surprising', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/səˈpɹaɪzɪŋ/', 'audio/surprising.mp3', 'To cause (someone) to feel unusually alarmed or delighted by something unexpected.', 'It surprises me that I owe twice as much as I thought I did.', 'Emotions & Feelings', 'đáng ngạc nhiên', 'Khiến (ai đó) cảm thấy báo động hoặc vui mừng một cách khác thường bởi điều gì đó bất ngờ.', 'Tôi ngạc nhiên khi biết mình nợ gấp đôi số tôi nghĩ.'),
    ('ed80621e-9db8-5e37-9fdd-d4e469098e5f', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'thought', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/θɔːt/', 'audio/thought.mp3', 'To ponder, to go over in one''s head.', 'Idly, the detective thought what his next move should be.', 'Emotions & Feelings', 'suy nghĩ, ý nghĩ', 'Suy ngẫm, xem xét trong đầu.', 'Một cách thờ ơ, viên thám tử suy nghĩ xem bước đi tiếp theo của mình nên là gì.'),
    ('74c5836d-3590-5736-a5f7-f59d8c26c807', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'trouble', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈtɹʌb(ə)l/', 'audio/trouble.mp3', 'A distressing or dangerous situation.', 'He was in trouble when the rain started.', 'Emotions & Feelings', 'rắc rối, phiền phức', 'Một tình huống đau buồn hoặc nguy hiểm.', 'Anh ấy gặp rắc rối khi trời bắt đầu mưa.'),
    ('9edd21eb-067a-5360-8d05-9e8567a2f104', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'unhappy', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ʌnˈhæpi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/unhappy-us.mp3', 'An individual who is not happy.', 'An unhappy customer is unlikely to return to your shop.', 'Emotions & Feelings', 'không vui, buồn', 'Một cá nhân không hạnh phúc.', 'Một khách hàng không hài lòng khó có thể quay lại cửa hàng của bạn.'),
    ('b35ddbd1-37f8-5a71-913e-4caab158f0fd', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'wish', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "A2"}]'::jsonb, '/wɪʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/wish-us.mp3', 'A desire, hope, or longing for something or for something to happen.', 'My dearest wish is to see them happily married.', 'Emotions & Feelings', 'ước', 'Mong muốn, hy vọng, hoặc khao khát điều gì đó hoặc điều gì đó xảy ra.', 'Điều ước tha thiết nhất của tôi là thấy họ kết hôn hạnh phúc.'),
    ('7f800832-f306-5a20-84f2-0b408d7b5679', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'worried', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈwʌɹid/', 'audio/worried.mp3', 'Thinking about unpleasant things that have happened or that might happen; feeling afraid and unhappy.', 'She was worried about her son who had been sent off to fight in the war.', 'Emotions & Feelings', 'lo lắng', 'Suy nghĩ về những điều khó chịu đã xảy ra hoặc có thể xảy ra; cảm thấy sợ hãi và không vui.', 'Cô ấy lo lắng về con trai mình, người đã được gửi đi chiến đấu trong chiến tranh.'),
    ('f284683c-1917-5813-aed0-282f45430b78', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'worry', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "B1"}]'::jsonb, '/ˈwɒɹi/', 'audio/worry.mp3', 'A strong feeling of anxiety.', 'I''m afflicted by worry throughout the night.', 'Emotions & Feelings', 'lo âu', 'Một cảm giác lo lắng mạnh mẽ.', 'Tôi bị ám ảnh bởi lo âu suốt đêm.'),
    ('acc96b43-8fcd-5746-924e-b8ede0e4c3ce', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'worse', 'A2', '["adj", "adv", "n"]'::jsonb, '[{"pos": "adj", "level": "A2"}, {"pos": "adv", "level": "B1"}, {"pos": "n", "level": "B2"}]'::jsonb, '/wɜːs/', 'audio/worse.mp3', 'Unfavorable; negative; not good.', 'Abducting children is bad for mothers.', 'Emotions & Feelings', 'tệ hơn', 'Không thuận lợi; tiêu cực; không tốt.', 'Bắt cóc trẻ em là xấu đối với các bà mẹ.'),
    ('01766af0-7c53-5b96-8055-e35b30beb55c', 'b4902f40-27b2-5236-8a19-7015e19ded09', 'worst', 'A2', '["adj", "adv", "n"]'::jsonb, '[{"pos": "adj", "level": "A2"}, {"pos": "adv", "level": "B1"}, {"pos": "n", "level": "B2"}]'::jsonb, '/wɜːst/', 'audio/worst.mp3', 'Unfavorable; negative; not good.', 'Abducting children is bad for mothers.', 'Emotions & Feelings', 'tệ nhất', 'Không thuận lợi; tiêu cực; không tốt.', 'Bắt cóc trẻ em là xấu đối với các bà mẹ.')
