    ('9701f500-04f0-5286-a4b8-fa795a8e4ea2', 'cb1a29b7-2215-5ce0-b710-fb1d29fe9eea', 'accident', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈæk.sə.dənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/accident-us.mp3', 'An unexpected event with negative consequences occurring without the intention of the one suffering the consequences.', 'to die by an accident', 'Health & Body', 'tai nạn', 'Một sự kiện bất ngờ với hậu quả tiêu cực xảy ra mà không có ý định của người chịu hậu quả.', 'chết vì tai nạn'),
