    ('b4439886-bf63-5948-9d1a-a99de79cf5e5', 'cb1a29b7-2215-5ce0-b710-fb1d29fe9eea', 'pain', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/peɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pain-1-uk.mp3', 'An ache or bodily suffering, or an instance of this; an unpleasant sensation, resulting from a derangement of functions, disease, or injury by violence; hurt.', 'I had to stop running when I started getting pains in my feet.', 'Health & Body', 'cơn đau', 'Một cơn đau hoặc sự đau đớn về thể xác, hoặc một trường hợp của điều này; một cảm giác khó chịu, do rối loạn chức năng, bệnh tật hoặc chấn thương bạo lực gây ra; tổn thương.', 'Tôi phải dừng chạy khi bắt đầu cảm thấy đau ở bàn chân.'),
    ('eca646fe-2a80-55b1-a189-873e068d4e15', 'cb1a29b7-2215-5ce0-b710-fb1d29fe9eea', 'patient', 'A2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "adj", "level": "B2"}]'::jsonb, '/ˈpeɪʃənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/patient-uk.mp3', 'A person or animal who receives treatment from a doctor or other medically educated person.', 'The subject of a passive verb is usually a patient.', 'Health & Body', 'bệnh nhân, kiên nhẫn', 'Một người hoặc động vật nhận được sự điều trị từ bác sĩ hoặc người có học vấn y khoa khác.', 'Chủ ngữ của một động từ bị động thường là đối tượng chịu tác động.'),
