    ('90dee05e-cf0f-5b4d-942f-b2b6b0c1cd2a', 'cb1a29b7-2215-5ce0-b710-fb1d29fe9eea', 'weak', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/wiːk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/weak-us.mp3', 'Lacking in force (usually strength) or ability.', 'The child was too weak to move the boulder.', 'Health & Body', 'yếu', 'Thiếu lực (thường là sức mạnh) hoặc khả năng.', 'Đứa trẻ quá yếu để di chuyển tảng đá.'),
    ('1c3554e3-aacc-5c83-bd2b-332c5744a283', 'cb1a29b7-2215-5ce0-b710-fb1d29fe9eea', 'weight', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/weɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/weight-us.mp3', '(physical) Matter, material.', 'He''s working out with weights.', 'Health & Body', 'tạ, trọng lượng', '(vật lý) Vật chất, vật liệu.', 'Anh ấy đang tập luyện với tạ.'),
    ('997829d4-093e-554a-ad5d-2d84056da7e1', 'cb1a29b7-2215-5ce0-b710-fb1d29fe9eea', 'ankle', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈæŋ.kəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ankle-us.mp3', 'The skeletal joint which connects the foot with the leg; the uppermost portion of the foot and lowermost portion of the leg, which contain this skeletal joint.', NULL, 'Health & Body', 'mắt cá chân', 'Khớp xương nối bàn chân với cẳng chân; phần trên cùng của bàn chân và phần dưới cùng của cẳng chân, chứa khớp xương này.', NULL),
    ('063c49aa-2faf-55fa-aa24-c5862a7720b8', 'cb1a29b7-2215-5ce0-b710-fb1d29fe9eea', 'boil', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/bɔɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/boil-uk.mp3', 'A localized accumulation of pus in the skin, resulting from infection.', NULL, 'Health & Body', 'đun sôi', 'Sự tích tụ cục bộ của mủ trong da, do nhiễm trùng.', NULL),
    ('97b1760a-1e0d-5939-88a3-2fdcc615f134', 'cb1a29b7-2215-5ce0-b710-fb1d29fe9eea', 'dentist', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈdɛntɪst/', 'audio/dentist.mp3', 'A medical doctor who specializes in dentistry.', NULL, 'Health & Body', 'nha sĩ', 'Bác sĩ y khoa chuyên về nha khoa.', NULL)
