    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('312a4bf8-7e27-5ffa-99bc-3d4e9849d4ad', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'bin', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/bɪn/', 'audio/bin.mp3', 'A box, frame, crib, or enclosed place, used as a storage container.', 'a corn bin; a wine bin; a coal bin', 'Home & Living', 'thùng', 'Một cái hộp, khung, nôi, hoặc nơi có vách bao, được dùng làm thùng chứa để lưu trữ.', 'thùng ngô; thùng rượu; thùng than'),
    ('f17a3cd4-ddf8-5feb-99d6-515be9e6b00d', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'board', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B1"}]'::jsonb, '/bɔːd/', 'audio/board.mp3', 'A relatively long, wide and thin piece of any material, usually wood or similar, often for use in construction or furniture-making.', 'Each player starts the game with four counters on the board.', 'Home & Living', 'tấm ván', 'Một mảnh tương đối dài, rộng và mỏng của bất kỳ vật liệu nào, thường là gỗ hoặc tương tự, thường dùng trong xây dựng hoặc làm đồ nội thất.', 'Mỗi người chơi bắt đầu trò chơi với bốn quân cờ trên bàn cờ.'),
    ('c46f7132-ddb8-57ed-b9a3-f2742bfc779e', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'brush', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "A2"}]'::jsonb, '/bɹʌʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/brush-us.mp3', 'An implement consisting of multiple more or less flexible bristles or other filaments attached to a handle, used for any of various purposes including cleaning, painting, and arranging hair.', 'She gave her hair a quick brush.', 'Home & Living', 'cái chổi', 'Một dụng cụ bao gồm nhiều sợi lông hoặc sợi khác linh hoạt hơn hoặc ít hơn gắn vào một tay cầm, được sử dụng cho bất kỳ mục đích nào bao gồm làm sạch, sơn và chải tóc.', 'Cô ấy chải nhanh mái tóc của mình.'),
    ('9c30a859-24c8-5d68-a182-e96b60335128', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'button', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈbʌtn̩/', 'audio/button.mp3', 'One who adjusts, especially for the insurance industry''s employment title "loss adjuster" (or "claims adjuster" in the United States).', 'April fastened the buttons of her overcoat to keep out the wind.', 'Home & Living', 'cái nút', 'Người điều chỉnh, đặc biệt cho chức danh nghề nghiệp ''người điều chỉnh tổn thất'' (hoặc ''người điều chỉnh yêu cầu bồi thường'' ở Hoa Kỳ) của ngành bảo hiểm.', 'April cài các nút áo khoác của cô ấy để chặn gió.'),
    ('b217060b-2fbf-5ba6-827a-89fe3151c2bd', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'carpet', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈkɑː(ɹ)pɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/carpet-uk.mp3', 'A fabric used as a complete floor covering.', 'After the fire, they carpeted over the blackened hardwood flooring.', 'Home & Living', 'thảm', 'Một loại vải được sử dụng làm lớp phủ sàn hoàn chỉnh.', 'Sau vụ cháy, họ trải thảm lên sàn gỗ bị đen.'),
    ('34dcf123-07fd-541d-b9b3-29c885120e2d', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'chip', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/tʃɪp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/chip-au.mp3', 'A small piece broken from a larger piece of solid material.', 'This cup has a chip in it.', 'Home & Living', 'vết sứt, mảnh vỡ', 'Một mảnh nhỏ vỡ ra từ một mảnh lớn hơn của vật liệu rắn.', 'Chiếc cốc này có một vết sứt.'),
    ('9a663b1c-4cfc-59fa-9839-cbd61a200134', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'comfortable', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈkʌm.fə.tə.bəl/', 'audio/comfortable.mp3', 'A stuffed or quilted coverlet for a bed; a comforter.', 'This is the most comfortable bed I''ve ever slept in.', 'Home & Living', 'thoải mái', 'Một tấm phủ có nhồi bông hoặc chần cho giường; một tấm chăn.', 'Đây là chiếc giường thoải mái nhất tôi từng ngủ.'),
    ('e2018f2d-7432-5774-a422-8d9bd4825f96', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'corner', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈkɔːnə(ɹ)/', 'audio/corner.mp3', 'The point where two converging lines meet; an angle, either external or internal.', 'The corners of the wire mesh were reinforced with little blobs of solder.', 'Home & Living', 'góc', 'Điểm gặp nhau của hai đường hội tụ; một góc, bên ngoài hoặc bên trong.', 'Các góc của lưới kim loại được gia cố bằng những đốm hàn nhỏ.'),
    ('c4d19e25-b115-546b-9909-90db6a09f3bf', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'cover', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "B1"}]'::jsonb, '/ˈkʌvə/', 'audio/cover.mp3', 'A lid.', 'The soldiers took cover behind a ruined building.', 'Home & Living', 'che phủ', 'Một cái nắp.', 'Những người lính ẩn nấp sau một tòa nhà đổ nát.'),
    ('e55d9a36-0f5c-55ca-85cf-e49942f75c75', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'cupboard', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈkʌbəd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cupboard-uk.mp3', 'A board or table used to openly hold and display silver plate and other dishware; a sideboard; a buffet.', 'Put the cups back into the cupboard.', 'Home & Living', 'tủ bếp', 'Một tấm ván hoặc bàn dùng để trưng bày công khai đồ bạc và các đồ dùng bằng đĩa khác; một tủ trưng bày; một bàn buffet.', 'Cất các cốc trở lại vào tủ bếp.'),
    ('55440858-d6e3-5454-ac1a-83dbb4f4d5ae', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'fix', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ˈfɪks/', 'audio/fix.mp3', 'A repair or corrective action.', 'That plumber''s fix is much better than the first one''s.', 'Home & Living', 'sửa chữa', 'Một hành động sửa chữa hoặc khắc phục.', 'Cách sửa của thợ sửa ống nước đó tốt hơn nhiều so với người đầu tiên.'),
    ('1f15028a-d01b-536f-9bc7-7edcac67057e', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'fork', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/fɔːk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fork-uk.mp3', 'A pronged tool having a long straight handle, used for digging, lifting, throwing etc.', 'West Fork White River and East Fork White River join together to form the White River of Indiana.', 'Home & Living', 'cái nĩa', 'Một công cụ có nhiều ngạnh với tay cầm dài thẳng, dùng để đào, nâng, ném, v.v.', 'West Fork White River và East Fork White River hợp lại với nhau để tạo thành White River của Indiana.'),
    ('9db2413f-2eac-5bc4-9f98-7687d4b5a4ab', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'furniture', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈfɜːnɪtʃə/', 'audio/furniture.mp3', 'Large movable item(s), usually in a room, which enhance(s) the room''s characteristics, functionally or decoratively.', 'A chair is furniture. Sofas are also furniture.', 'Home & Living', 'đồ nội thất', 'Vật dụng lớn có thể di chuyển, thường trong một căn phòng, giúp tăng cường đặc điểm của phòng về mặt chức năng hoặc trang trí.', 'Ghế là đồ nội thất. Ghế sofa cũng là đồ nội thất.'),
    ('6f41ab4f-1c46-5a1c-bd75-c0f192e88da4', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'gate', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɡeɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/gate-au.mp3', 'A doorlike structure outside a house.', 'The gate in front of the railroad crossing went up after the train had passed.', 'Home & Living', 'cổng', 'Một cấu trúc giống cửa bên ngoài một ngôi nhà.', 'Cổng trước đường ray xe lửa đã mở lên sau khi đoàn tàu đi qua.'),
    ('56b5822e-d4e2-5d03-82d1-cebf1b7dd8c4', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'guest', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɡɛst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/guest-us.mp3', 'A recipient of hospitality, specifically someone staying by invitation at the house of another.', 'The guests were let in by the butler.', 'Home & Living', 'khách', 'Người nhận sự hiếu khách, cụ thể là ai đó ở lại theo lời mời tại nhà của người khác.', 'Các vị khách được quản gia cho vào.'),
    ('0e4b9ffa-45a1-5440-a21e-10ab716a71aa', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'hall', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/hɔːl/', 'audio/hall.mp3', 'A corridor; a hallway.', 'The drinking fountain was out in the hall.', 'Home & Living', 'hành lang', 'Một lối đi; một hành lang.', 'Vòi nước uống ở ngoài hành lang.'),
    ('b4472aab-e5f5-5ed7-baa5-742172256883', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'hide', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/haɪd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/hide-us.mp3', 'To put (something) in a place where it will be harder to discover or out of sight.', 'He hides his magazines under the bed.', 'Home & Living', 'giấu', 'Đặt (thứ gì đó) vào một nơi mà nó sẽ khó bị phát hiện hơn hoặc ra khỏi tầm nhìn.', 'Anh ấy giấu tạp chí của mình dưới gầm giường.'),
    ('5cfb33b8-fe00-55f9-8b02-3188cb88929c', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'hole', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/həʊl/', 'audio/hole.mp3', 'A hollow place or cavity; an excavation; a pit; an opening in or through a solid body, a fabric, etc.; a perforation; a rent; a fissure.', 'There’s a hole in my shoe. Her stocking has a hole in it.', 'Home & Living', 'lỗ', 'Một nơi rỗng hoặc khoang; một cái hố; một cái hố; một lỗ mở trong hoặc xuyên qua một vật thể rắn, một cấu trúc, v.v.; một lỗ khoan; một vết rách; một vết nứt.', 'Có một lỗ trên giày của tôi. Tất của cô ấy có một lỗ.'),
    ('902d3854-ba41-59c1-b46a-5de726a5cb3b', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'inside', 'A2', '["prep", "adv", "n", "adj"]'::jsonb, '[{"pos": "prep", "level": "A2"}, {"pos": "adv", "level": "A2"}, {"pos": "n", "level": "A2"}, {"pos": "adj", "level": "A2"}]'::jsonb, '/ɪnˈsaɪd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/inside-us.mp3', 'The interior or inner part.', 'The inside of the building has been extensively restored.', 'Home & Living', 'bên trong', 'Phần nội thất hoặc bên trong.', 'Bên trong tòa nhà đã được phục hồi rộng rãi.'),
    ('c35cadf3-c915-5ee3-82ce-15664a1055b3', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'knock', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "B1"}]'::jsonb, '/nɒk/', 'audio/knock.mp3', 'Sudden fatigue as a result of glycogen depletion from not having taken in enough nutrition.', 'I heard a knock on my door.', 'Home & Living', 'gõ cửa', 'Sự mệt mỏi đột ngột do cạn kiệt glycogen vì không nạp đủ dinh dưỡng.', 'Tôi nghe thấy tiếng gõ cửa.'),
    ('3a2b5f77-effb-52fa-87ff-c94f16f8a0cd', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'lock', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "A2"}]'::jsonb, '/lɒk/', 'audio/lock.mp3', 'Something used for fastening, which can only be opened with a key or combination.', 'If you put the brakes on too hard, the wheels will lock.', 'Home & Living', 'khóa', 'Thứ gì đó dùng để khóa, chỉ có thể mở bằng chìa khóa hoặc mật mã.', 'Nếu bạn phanh quá gấp, các bánh xe sẽ bị khóa.'),
    ('1cc0c226-a5b5-5573-a1d0-fed0ac45b247', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'mirror', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈmɘ.ɹɘ/', 'audio/mirror.mp3', 'A smooth surface, usually made of glass with reflective material painted on the underside, that reflects light so as to give an image of what is in front of it.', 'I had a look in the mirror to see if the blood had come off my face.', 'Home & Living', 'gương', 'Một bề mặt nhẵn, thường làm bằng thủy tinh với vật liệu phản chiếu được sơn ở mặt dưới, phản chiếu ánh sáng để tạo ra hình ảnh của những gì ở trước nó.', 'Tôi đã nhìn vào gương để xem máu đã sạch khỏi mặt tôi chưa.'),
    ('796be169-eb8e-5c47-855d-6e38ab7f4ca5', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'noise', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/nɔɪz/', 'https://api.dictionaryapi.dev/media/pronunciations/en/noise-uk.mp3', 'Various sounds, usually unwanted or unpleasant.', 'He knew that it was trash day, when the garbage collectors made all the noise.', 'Home & Living', 'tiếng ồn', 'Các âm thanh khác nhau, thường không mong muốn hoặc khó chịu.', 'Anh ấy biết rằng hôm đó là ngày đổ rác, khi những người thu gom rác tạo ra tất cả tiếng ồn.'),
    ('e112d4ec-9fcf-55e7-86ff-e496a023b07e', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'noisy', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈnɔːɪzɪ/', 'audio/noisy.mp3', 'Making a noise, especially a loud unpleasant sound', 'the noisy crowd.', 'Home & Living', 'ồn ào', 'Tạo ra tiếng ồn, đặc biệt là âm thanh lớn khó chịu.', 'đám đông ồn ào.'),
    ('2b97dd01-07a0-5de4-992e-93caab3c97e7', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'pocket', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈpɒkɪt/', 'audio/pocket.mp3', 'A bag stitched to an item of clothing, used for carrying small items.', 'I paid for it out of my own pocket.', 'Home & Living', 'túi', 'Một cái túi được may vào quần áo, dùng để đựng các vật nhỏ.', 'Tôi đã trả tiền cho nó từ túi của chính mình.'),
    ('d6dda8da-d420-544f-b9ca-1e1a288a52c4', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'possession', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/pəˈzɛʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/possession-us.mp3', 'Control or occupancy of something for which one does not necessarily have private property rights.', 'I would gladly give all of my worldly possessions just to be able to do that.', 'Home & Living', 'sự sở hữu', 'Quyền kiểm soát hoặc chiếm giữ thứ gì đó mà người ta không nhất thiết có quyền sở hữu tư nhân.', 'Tôi sẽ sẵn lòng cho đi tất cả tài sản trần thế của mình chỉ để có thể làm điều đó.'),
    ('bdfcf945-4f2d-536a-9d70-5e5297ef91a0', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'provide', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/pɹəˈvaɪd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/provide-us.mp3', 'To make a living; earn money for necessities.', 'It is difficult to provide for my family working on minimum wage.', 'Home & Living', 'cung cấp', 'Để kiếm sống; kiếm tiền cho những nhu cầu thiết yếu.', 'Thật khó để chu cấp cho gia đình tôi khi làm việc với mức lương tối thiểu.'),
    ('eaa68d6e-4123-52f4-93ef-01f80a709db4', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'remove', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ɹɪˈmuːv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/remove-au.mp3', 'The act of removing something.', 'He removed the marbles from the bag.', 'Home & Living', 'loại bỏ', 'Hành động loại bỏ thứ gì đó.', 'Anh ấy lấy những viên bi ra khỏi túi.'),
    ('c8d06201-85c2-5848-906b-6aec1ad3c4ab', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'repair', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "B1"}]'::jsonb, '/ɹɪˈpɛə/', 'audio/repair.mp3', 'The act of repairing something.', 'I took the car to the workshop for repair.', 'Home & Living', 'sửa chữa', 'Hành động sửa chữa thứ gì đó.', 'Tôi đã đưa xe đến xưởng để sửa chữa.'),
    ('28dc02c7-bb2e-5dc2-ba2f-cdc7bd71f5e6', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'replace', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ɹɪˈpleɪs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/replace-us.mp3', 'To restore to a former place, position, condition, etc.; to put back', 'When you''ve finished using the telephone, please replace the handset.', 'Home & Living', 'thay thế', 'Khôi phục về vị trí, tình trạng, v.v. trước đây; đặt lại', 'Khi bạn sử dụng xong điện thoại, vui lòng đặt ống nghe lại chỗ cũ.'),
    ('c0b44aed-5398-5c9b-b636-0616196e2b5b', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'roof', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɹuːf/', 'https://api.dictionaryapi.dev/media/pronunciations/en/roof-ca.mp3', 'The external covering at the top of a building.', 'The roof was blown off by the tornado.', 'Home & Living', 'mái nhà', 'Lớp phủ bên ngoài ở đỉnh của một tòa nhà.', 'Mái nhà bị thổi bay bởi cơn lốc xoáy.'),
    ('37ad4fa9-f1af-54a6-abf8-f27835f6d04e', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'rubbish', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈɹʌbɪʃ/', 'audio/rubbish.mp3', 'Refuse, waste, garbage, junk, trash.', 'The rubbish is collected every Thursday in Gloucester, but on Wednesdays in Cheltenham.', 'Home & Living', 'rác', 'Đồ bỏ đi, chất thải, rác, đồ vô giá trị.', 'Rác được thu gom mỗi thứ Năm ở Gloucester, nhưng vào thứ Tư ở Cheltenham.'),
    ('1fc35f08-2938-595c-b57d-7916f0e618d0', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'safe', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/seɪf/', 'https://api.dictionaryapi.dev/media/pronunciations/en/safe-us.mp3', 'A box, usually made of metal, in which valuables can be locked for safekeeping.', 'You’ll be safe here.', 'Home & Living', 'an toàn', 'Một chiếc hộp, thường làm bằng kim loại, trong đó các vật có giá trị có thể được khóa lại để bảo quản an toàn.', 'Bạn sẽ an toàn ở đây.'),
    ('cb240ed0-4304-5eb9-abbe-827926c69011', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'seat', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/siːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/seat-us.mp3', 'Something to be sat upon.', 'Be sure to seat the gasket properly before attaching the cover.', 'Home & Living', 'chỗ ngồi', 'Thứ gì đó để ngồi lên.', 'Hãy chắc chắn lắp đặt miếng đệm đúng cách trước khi gắn nắp.'),
    ('a3819558-7cc5-5d50-bc44-0cf40e7533ad', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'sheet', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ʃiːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sheet-uk.mp3', 'A thin bed cloth used as a covering for a mattress or as a layer over the sleeper.', 'Use the sheets in the hall closet to make the bed.', 'Home & Living', 'tấm ga', 'Một tấm vải giường mỏng được sử dụng làm lớp phủ cho nệm hoặc như một lớp trên người ngủ.', 'Sử dụng ga trải giường trong tủ hành lang để dọn giường.'),
    ('50b47ac2-fcc3-59b1-bc5a-75f61715ac8b', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'shut', 'A2', '["v", "adj"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "adj", "level": "A2"}]'::jsonb, '/ʃʌt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/shut-us.mp3', 'Closed, shut.', 'a close alley; close quarters', 'Home & Living', 'đóng lại', 'Đã đóng, khép.', 'một ngõ hẻm kín; khoảng cách gần'),
    ('d832e8c3-4f6b-5033-94ae-7f1cab92437b', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'soap', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/səʊp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/soap-uk.mp3', 'A substance able to mix with both oil and water, used for cleaning, often in the form of a solid bar or in liquid form, derived from fats or made synthetically.', 'I tried washing my hands with soap, but the stain wouldn''t go away.', 'Home & Living', 'xà phòng', 'Một chất có khả năng hòa trộn với cả dầu và nước, dùng để làm sạch, thường ở dạng bánh rắn hoặc dạng lỏng, có nguồn gốc từ chất béo hoặc được tổng hợp nhân tạo.', 'Tôi đã thử rửa tay bằng xà phòng, nhưng vết bẩn không chịu đi.'),
    ('068b67a2-e77f-5ede-b9bb-fee4cb123bef', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'spoon', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/spuːn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/spoon-uk.mp3', 'An implement for eating or serving; a scooped utensil whose long handle is straight, in contrast to a ladle.', 'Sarah spooned some apple sauce onto her plate.', 'Home & Living', 'cái thìa', 'Dụng cụ để ăn hoặc phục vụ; một dụng cụ có hình múc với cán dài thẳng, trái ngược với cái muôi.', 'Sarah múc một ít sốt táo lên đĩa của cô ấy.'),
    ('5c3a46f2-38f1-5347-bcef-11a875bd9c0a', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'tidy', 'A2', '["adj", "v"]'::jsonb, '[{"pos": "adj", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/ˈtaɪdi/', 'audio/tidy.mp3', 'A tabletop container for pens and stationery.', 'a desk tidy', 'Home & Living', 'gọn gàng', 'Một hộp đựng để trên bàn cho bút và đồ dùng văn phòng.', 'hộp đựng đồ trên bàn làm việc'),
    ('6c5b1abd-6f92-5adb-a8f2-8fbd8c79169c', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'towel', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/taʊl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/towel-uk.mp3', 'A cloth used for wiping, especially one used for drying anything wet, as a person after a bath.', 'He got out of the shower and toweled himself dry.', 'Home & Living', 'khăn tắm', 'Một miếng vải dùng để lau, đặc biệt là một miếng dùng để lau khô bất cứ thứ gì ướt, như một người sau khi tắm.', 'Anh ấy bước ra khỏi vòi sen và lau khô người bằng khăn.'),
    ('c4e3a6a3-23d9-5e1c-9e9e-8338d4894313', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'washing', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈwɒʃɪŋ/', 'audio/washing.mp3', 'To clean with water.', 'Dishwashers wash dishes much more efficiently than most humans.', 'Home & Living', 'giặt giũ', 'Làm sạch bằng nước.', 'Máy rửa bát rửa bát hiệu quả hơn nhiều so với hầu hết con người.'),
    ('c52602f4-712b-5589-9f8d-cd4ece536404', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'wooden', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈwʊdən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/wooden-us.mp3', 'Made of wood.', 'On a recent windy day, hundreds of visitors climbed wooden stairs to take pictures in front of the glacier.', 'Home & Living', 'bằng gỗ', 'Làm bằng gỗ.', 'Vào một ngày gió gần đây, hàng trăm du khách đã leo lên cầu thang gỗ để chụp ảnh trước sông băng.'),
    ('a1a3277f-3591-5472-ab6b-f8a2b6b1678f', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'cooker', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈkʊkə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cooker-uk.mp3', 'A device for heating food, a stove.', NULL, 'Home & Living', 'bếp', 'Thiết bị để làm nóng thức ăn, một cái bếp.', NULL),
    ('fe7ea958-bf23-513e-a2ef-6ac5a2e8c981', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'fridge', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/fɹɪd͡ʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fridge-uk.mp3', 'A refrigerator.', NULL, 'Home & Living', 'tủ lạnh', 'Một cái tủ lạnh.', NULL),
    ('09f71592-431f-5fac-8b3d-6b723f6e49ec', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'knife', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/naɪf/', 'https://api.dictionaryapi.dev/media/pronunciations/en/knife-uk.mp3', 'A utensil or a tool designed for cutting, consisting of a flat piece of hard material, usually steel or other metal (the blade), usually sharpened on one edge, attached to a handle. The blade may be pointed for piercing.', NULL, 'Home & Living', 'dao', 'Một dụng cụ hoặc công cụ được thiết kế để cắt, bao gồm một miếng vật liệu cứng phẳng, thường là thép hoặc kim loại khác (lưỡi dao), thường được mài sắc ở một cạnh, gắn vào một cán. Lưỡi dao có thể được...', NULL),
    ('8ac0b36c-b6e3-51b5-9875-e33d7e07abda', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'lamp', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/læmp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lamp-uk.mp3', 'A device that generates heat, light or other radiation. Especially an electric light bulb.', NULL, 'Home & Living', 'đèn', 'Một thiết bị tạo ra nhiệt, ánh sáng hoặc bức xạ khác. Đặc biệt là bóng đèn điện.', NULL),
    ('8b4e1b37-5b19-57df-828a-0619f65ed97e', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'oven', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈʌ.vn̩/', 'audio/oven.mp3', 'A chamber used for baking or heating.', NULL, 'Home & Living', 'lò nướng', 'Một buồng được sử dụng để nướng hoặc làm nóng.', NULL),
    ('c05b6395-b61f-5028-91a5-8e76fc21aa59', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'stair', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/stɛə/', 'audio/stair.mp3', 'A single step in a staircase.', NULL, 'Home & Living', 'bậc thang', 'Một bậc đơn lẻ trong cầu thang.', NULL),
    ('9c5654d7-a156-5740-afeb-b1b80a49e3f9', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'tower', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈtaʊ.ə(ɹ)/', 'audio/tower.mp3', 'A very tall iron-framed structure, usually painted red and white, on which microwave, radio, satellite, or other communication antennas are installed; mast.', NULL, 'Home & Living', 'tháp', 'Một cấu trúc khung sắt rất cao, thường được sơn màu đỏ và trắng, trên đó lắp đặt các ăng-ten vi sóng, radio, vệ tinh hoặc thông tin liên lạc khác; cột.', NULL),
    ('df53b1b4-cf51-5b53-8378-95b3087ceb6e', '6b9e27fc-d1ea-5221-9691-c4cd091618f1', 'can2', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, NULL, 'audio/can2.mp3', NULL, NULL, 'Home & Living', 'lon, hộp', NULL, NULL)
