INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('0a4689b4-bccc-5722-82b4-c45b664c2cf1', '819f09d5-5c6d-570b-b196-46a1afe97722', 'ancient', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈeɪn.ʃənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ancient-us.mp3', 'A person who is very old.', 'an ancient city an ancient forest', 'Society & Culture', 'cổ đại', 'Một người rất già.', 'một thành phố cổ đại một khu rừng cổ đại'),
    ('983192df-c873-5def-85a3-908c409ffec4', '819f09d5-5c6d-570b-b196-46a1afe97722', 'background', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈbæk.ɡɹaʊnd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/background-us.mp3', 'One''s social heritage, or previous life; what one did in the past.', 'The lawyer had a background in computer science.', 'Society & Culture', 'lý lịch, nền tảng', 'Di sản xã hội, hoặc cuộc sống trước đây của một người; những gì người đó đã làm trong quá khứ.', 'Luật sư đó có nền tảng về khoa học máy tính.'),
    ('d5429a6d-16fd-5e2f-9bd2-b877d9d00a3e', '819f09d5-5c6d-570b-b196-46a1afe97722', 'cause', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/kɔːz/', 'audio/cause.mp3', '(often with of, typically of adverse results) The source of, or reason for, an event or action; that which produces or effects a result.', 'They identified a burst pipe as the cause of the flooding.', 'Society & Culture', 'nguyên nhân', '(thường đi với ''of'', thường là kết quả tiêu cực) Nguồn gốc, hoặc lý do, của một sự kiện hoặc hành động; thứ tạo ra hoặc gây ra một kết quả.', 'Họ xác định một đường ống vỡ là nguyên nhân của trận lụt.'),
    ('b90c79f9-5c1b-53cf-82b2-b0cbad93c1f4', '819f09d5-5c6d-570b-b196-46a1afe97722', 'celebrate', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ˈsɛl.ə.bɹeɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/celebrate-us.mp3', 'To extol or honour in a solemn manner.', 'to celebrate the name of the Most High', 'Society & Culture', 'ăn mừng', 'Tán dương hoặc tôn vinh một cách trang trọng.', 'để ca ngợi danh của Đấng Tối Cao'),
    ('884b5bf4-5248-5f79-85a7-a7007d20f848', '819f09d5-5c6d-570b-b196-46a1afe97722', 'church', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/t͡ʃɜːt͡ʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/church-uk.mp3', 'A Christian house of worship; a building where Christian religious services take place.', 'There is a lovely little church in the valley.', 'Society & Culture', 'nhà thờ', 'Nơi thờ phụng của Cơ đốc giáo; một tòa nhà nơi diễn ra các buổi lễ tôn giáo Cơ đốc.', 'Có một nhà thờ nhỏ xinh xắn trong thung lũng.'),
    ('d1f85fc6-af7b-566b-aeec-ee0ebe42672e', '819f09d5-5c6d-570b-b196-46a1afe97722', 'community', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/k(ə)ˈmjunəti/', 'https://api.dictionaryapi.dev/media/pronunciations/en/community-ca.mp3', 'A group sharing a common understanding, and often the same language, law, manners, and/or tradition.', 'a community of goods', 'Society & Culture', 'cộng đồng', 'Một nhóm chia sẻ sự hiểu biết chung, và thường cùng ngôn ngữ, luật pháp, cách cư xử và/hoặc truyền thống.', 'cộng đồng của cải'),
