INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('e601ee98-e41e-56cb-a849-579841b4dfd1', 'b43d2532-fe89-594e-9f37-326935471d2e', 'active', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈæk.tɪv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/active-us.mp3', 'A person or thing that is acting or capable of acting.', 'certain active principles', 'Sports & Hobbies', 'năng động', 'Một người hoặc vật đang hành động hoặc có khả năng hành động.', 'một số nguyên tắc hoạt động nhất định'),
    ('5885457b-5a85-58b7-aaaf-229692904169', 'b43d2532-fe89-594e-9f37-326935471d2e', 'adventure', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ædˈvɛnt͡ʃɚ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/adventure-ca.mp3', 'The encountering of risks; a bold undertaking, in which dangers are likely to be encountered, and the issue is staked upon unforeseen events; a daring feat.', 'A life full of adventures.', 'Sports & Hobbies', 'cuộc phiêu lưu', 'Việc gặp phải rủi ro; một cuộc mạo hiểm táo bạo, trong đó có khả năng gặp nguy hiểm, và kết quả phụ thuộc vào những sự kiện không lường trước; một kỳ công táo bạo.', 'Một cuộc sống đầy phiêu lưu.'),
    ('f4153ae1-e4ce-5aa4-b1da-cbe98e351d16', 'b43d2532-fe89-594e-9f37-326935471d2e', 'athlete', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈæθ.lit/', 'audio/athlete.mp3', 'A participant in a group of sporting activities which includes track and field, road running, cross country running and racewalking.', 'She''s the first athlete in her sport to obtain a corporate sponsor.', 'Sports & Hobbies', 'vận động viên', 'Người tham gia vào một nhóm hoạt động thể thao bao gồm điền kinh, chạy đường trường, chạy việt dã và đi bộ thể thao.', 'Cô ấy là vận động viên đầu tiên trong môn thể thao của mình có được nhà tài trợ doanh nghiệp.'),
    ('f81b4d22-edd8-586f-a740-6c4348d97a57', 'b43d2532-fe89-594e-9f37-326935471d2e', 'bit', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/bɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bit-us.mp3', 'A piece of metal placed in a horse''s mouth and connected to the reins to direct the animal.', 'A horse hates having a bit put in its mouth.', 'Sports & Hobbies', 'khớp cắn', 'Một miếng kim loại đặt vào miệng ngựa và nối với dây cương để điều khiển con vật.', 'Con ngựa ghét bị đặt khớp cắn vào miệng.'),
    ('f1c2de84-7886-5f7f-9aa3-e5c9b602d27a', 'b43d2532-fe89-594e-9f37-326935471d2e', 'camp', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '[kʰɛəmp]', 'audio/camp.mp3', 'An outdoor place acting as temporary accommodation in tents or other temporary structures.', 'a hunter''s camp', 'Sports & Hobbies', 'cắm trại', 'Một địa điểm ngoài trời hoạt động như chỗ ở tạm thời trong lều hoặc các công trình tạm thời khác.', 'trại của thợ săn'),
    ('fdc3fe78-8cbe-58ce-bd6f-78be1d2a839e', 'b43d2532-fe89-594e-9f37-326935471d2e', 'camping', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈkæmpɪŋ/', 'audio/camping.mp3', 'To live in a tent or similar temporary accommodation.', 'We''re planning to camp in the field until Sunday.', 'Sports & Hobbies', 'cắm trại', 'Sống trong một chiếc lều hoặc chỗ ở tạm thời tương tự.', 'Chúng tôi dự định cắm trại trên cánh đồng cho đến Chủ nhật.'),
