    ('1fc1bdb3-470c-51c8-8017-fc02227b844a', 'b43d2532-fe89-594e-9f37-326935471d2e', 'toy', 'A2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "adj", "level": "A2"}]'::jsonb, '/tɔɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/toy-us.mp3', 'Something to play with, especially as intended for use by a child.', 'A grown man does not play with a child’s toy.', 'Sports & Hobbies', 'đồ chơi', 'Thứ gì đó để chơi, đặc biệt được thiết kế cho trẻ em sử dụng.', 'Một người đàn ông trưởng thành không chơi với đồ chơi trẻ con.'),
    ('317fd7b6-ba53-5ae6-9266-11568f4047f7', 'b43d2532-fe89-594e-9f37-326935471d2e', 'track', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/tɹæk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/track-au.mp3', 'A mark left by something that has passed along.', 'Can you see any tracks in the snow?', 'Sports & Hobbies', 'đường đua, dấu vết', 'Dấu vết để lại bởi thứ gì đó đã đi qua.', 'Bạn có thấy dấu vết nào trên tuyết không?'),
    ('360e37c1-5474-56f1-92f2-f446167e53ed', 'b43d2532-fe89-594e-9f37-326935471d2e', 'baseball', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈbeɪs.bɔːl/', 'audio/baseball.mp3', 'A sport common in North America, the Caribbean, and Japan, in which the object is to strike a ball so that one of a nine-person team can run counter-clockwise among four bases, resulting in the scoring of a run. The team with the most runs after termination of play, usually nine innings, wins.', NULL, 'Sports & Hobbies', 'bóng chày', 'Một môn thể thao phổ biến ở Bắc Mỹ, Caribe và Nhật Bản, trong đó mục tiêu là đánh bóng để một người trong đội chín người có thể chạy ngược chiều kim đồng hồ qua bốn gôn, dẫn đến việc ghi điểm.', NULL),
    ('3bbfb399-d45f-5893-9e05-36ca4882c6d0', 'b43d2532-fe89-594e-9f37-326935471d2e', 'basketball', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈbɑːs.kɪt.bɔːl/', 'audio/basketball.mp3', 'A sport in which two opposing teams of five players strive to put a ball through a hoop.', NULL, 'Sports & Hobbies', 'bóng rổ', 'Một môn thể thao trong đó hai đội đối lập gồm năm cầu thủ cố gắng đưa bóng vào rổ.', NULL),
    ('3c0f14fc-0082-5824-b45f-e6d01f12722e', 'b43d2532-fe89-594e-9f37-326935471d2e', 'compete', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/kəm.ˈpiːt/', 'audio/compete.mp3', 'To be in battle or in a rivalry with another for the same thing, position, or reward; to contend', NULL, 'Sports & Hobbies', 'cạnh tranh', 'Để chiến đấu hoặc trong một cuộc cạnh tranh với người khác cho cùng một thứ, vị trí, hoặc phần thưởng; để tranh đua', NULL),
    ('b9d1c78c-60cf-55f4-8a16-49fbc04cc146', 'b43d2532-fe89-594e-9f37-326935471d2e', 'golf', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɡɒlf/', 'audio/golf.mp3', 'A ball game played by individuals competing against one another in which the object is to hit a ball into each of a series of (usually 18 or nine) holes in the minimum number of strokes.', NULL, 'Sports & Hobbies', 'gôn', 'Một trò chơi bóng do các cá nhân thi đấu với nhau, trong đó mục tiêu là đánh bóng vào mỗi lỗ trong một loạt (thường là 18 hoặc 9 lỗ) với số cú đánh tối thiểu.', NULL),
    ('eb435a86-a6f1-54f9-96c0-9231476b3255', 'b43d2532-fe89-594e-9f37-326935471d2e', 'hockey', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈhɒki/', 'https://api.dictionaryapi.dev/media/pronunciations/en/hockey-1-us.mp3', 'Ice hockey, a game on ice in which two teams of six players skate and try to score by shooting a puck into the opposing team''s net, using their sticks.', NULL, 'Sports & Hobbies', 'khúc côn cầu', NULL, NULL),
    ('ca37ecc0-c18d-560a-9ef2-3d41e1101144', 'b43d2532-fe89-594e-9f37-326935471d2e', 'ski', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "A2"}]'::jsonb, '/ʃiː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ski-uk.mp3', 'One of a pair of long flat runners designed for gliding over snow or water', NULL, 'Sports & Hobbies', 'trượt tuyết/ván trượt', 'Một trong một cặp tấm trượt dài, phẳng được thiết kế để lướt trên tuyết hoặc nước', NULL),
    ('ac9e236f-cd27-5ed5-b408-699afca5d593', 'b43d2532-fe89-594e-9f37-326935471d2e', 'skiing', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈskiɪŋ/', 'audio/skiing.mp3', 'To move on skis', NULL, 'Sports & Hobbies', 'môn trượt tuyết', 'Di chuyển trên ván trượt tuyết', NULL),
    ('fb34d431-24b4-52e9-9705-a71272e9b64e', 'b43d2532-fe89-594e-9f37-326935471d2e', 'soccer', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈsɒk.ə/', 'audio/soccer.mp3', 'Association football', NULL, 'Sports & Hobbies', 'bóng đá', 'Bóng đá hiệp hội', NULL),
    ('ac319b64-9443-5fa0-95a9-e9c5f9a6ac5d', 'b43d2532-fe89-594e-9f37-326935471d2e', 'trainer', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈtɹeɪnə/', 'audio/trainer.mp3', 'A person who trains another; a coach.', NULL, 'Sports & Hobbies', 'huấn luyện viên', 'Người huấn luyện người khác; một huấn luyện viên.', NULL),
    ('12579b46-58ee-51e0-befe-fb8418b02806', 'b43d2532-fe89-594e-9f37-326935471d2e', 'winner', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈwɪnə/', 'audio/winner.mp3', 'One who has won or often wins.', NULL, 'Sports & Hobbies', 'người chiến thắng', 'Người đã thắng hoặc thường xuyên thắng.', NULL),
    ('9ea0f162-3d75-5a94-a4fe-0fa1193be11d', 'b43d2532-fe89-594e-9f37-326935471d2e', 'race (competition)', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, NULL, 'audio/race_(competition).mp3', NULL, NULL, 'Sports & Hobbies', 'cuộc đua', NULL, NULL)
