INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('17f7fa1b-d8f4-55e1-9c09-26742f62ef40', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'code', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/kəʊd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/code-uk.mp3', 'A short symbol, often with little relation to the item it represents.', 'This flavour of soup has been assigned the code WRT-9.', 'Technology & Media', 'mã', 'Một ký hiệu ngắn, thường có ít liên quan đến vật mà nó đại diện.', 'Hương vị súp này đã được gán mã WRT-9.'),
    ('216dc98c-e26e-5dfb-a8e5-536b82daeb67', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'connect', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/kəˈnɛkt/', 'audio/connect.mp3', '(of an object) To join (to another object): to attach, or to be intended to attach or capable of attaching, to another object.', 'I think this piece connects to that piece over there.', 'Technology & Media', 'kết nối', '(của một vật thể) Nối (với một vật thể khác): gắn vào, hoặc có ý định gắn hoặc có khả năng gắn vào một vật thể khác.', 'Tôi nghĩ mảnh này kết nối với mảnh kia ở đằng kia.'),
    ('f9165084-45d1-52d3-b79b-ac249f1902ab', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'connected', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/kəˈnɛktɪd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/connected-us.mp3', '(of an object) To join (to another object): to attach, or to be intended to attach or capable of attaching, to another object.', 'I think this piece connects to that piece over there.', 'Technology & Media', 'được kết nối', '(của một vật thể) Nối (với một vật thể khác): gắn vào, hoặc có ý định gắn hoặc có khả năng gắn vào một vật thể khác.', 'Tôi nghĩ mảnh này kết nối với mảnh kia ở đằng kia.'),
    ('5de98811-988e-5663-a717-41002e5c9f5f', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'device', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/dəˈvaɪs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/device-us.mp3', 'Any piece of equipment made for a particular purpose, especially a mechanical or electrical one.', 'There are a number of household devices in a kitchen such as a dishwasher, a garbage disposal, or an electric can opener.', 'Technology & Media', 'thiết bị', 'Bất kỳ thiết bị nào được tạo ra cho một mục đích cụ thể, đặc biệt là thiết bị cơ khí hoặc điện.', 'Có một số thiết bị gia dụng trong nhà bếp như máy rửa bát, máy nghiền rác hoặc máy mở hộp điện.'),
    ('769a991e-aebc-5eba-bb26-31a1925025c3', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'digital', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈdɪd͡ʒɪtəɫ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/digital-us.mp3', 'A digital option.', 'He moved to digital for the first time, using a Sony camera.', 'Technology & Media', 'kỹ thuật số', 'Một tùy chọn kỹ thuật số.', 'Anh ấy chuyển sang kỹ thuật số lần đầu tiên, sử dụng máy ảnh Sony.'),
    ('39e957f0-4a06-5ce8-ba43-bfc12f6eaed4', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'document', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈdɒkjʊmənt/', 'audio/document.mp3', 'An original or official paper used as the basis, proof, or support of anything else, including any writing, book, or other instrument conveying information pertinent to such proof or support.', 'He documented each step of the process as he did it, which was good when the investigation occurred.', 'Technology & Media', 'tài liệu', 'Một giấy tờ gốc hoặc chính thức được sử dụng làm cơ sở, bằng chứng hoặc hỗ trợ cho bất cứ thứ gì khác, bao gồm bất kỳ văn bản, sách hoặc công cụ nào khác truyền tải thông tin liên quan đến bằng chứng hoặc hỗ trợ đó.', 'Anh ấy đã ghi chép lại từng bước của quy trình khi thực hiện, điều này rất tốt khi cuộc điều tra diễn ra.'),
    ('81eb15c3-cafd-50f3-b8e1-b7c175a312a8', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'download', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "A2"}]'::jsonb, '/ˈdaʊnˌləʊd/', 'audio/download.mp3', 'A file transfer to the local computer.', 'The download took longer than I expected.', 'Technology & Media', 'tải xuống', 'Việc chuyển tệp xuống máy tính cục bộ.', 'Việc tải xuống mất nhiều thời gian hơn tôi dự kiến.'),
    ('4f13becf-23e7-58d3-99d1-03b27987332a', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'electric', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/əˈlɛktɹɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/electric-us.mp3', '(usually with definite article) Electricity; the electricity supply.', 'We had to sit in the dark because the electric was cut off.', 'Technology & Media', 'điện', '(thường với mạo từ xác định) Điện; nguồn cung cấp điện.', 'Chúng tôi phải ngồi trong bóng tối vì điện bị cắt.'),
    ('d42c0e9b-3963-5237-a561-7a98ed4e24ee', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'electricity', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɪˌlɛkˈtɹɪsɪti/', 'audio/electricity.mp3', 'Originally, a property of amber and certain other nonconducting substances to attract lightweight material when rubbed, or the cause of this property; now understood to be a phenomenon caused by the distribution and movement of charged subatomic particles and their interaction with the electromagnetic field.', 'Opening night for the new production had an electricity unlike other openings.', 'Technology & Media', 'điện', 'Ban đầu, một đặc tính của hổ phách và một số chất không dẫn điện khác để hút vật liệu nhẹ khi cọ xát, hoặc nguyên nhân của đặc tính này; nay được hiểu là hiện tượng gây ra bởi sự dịch chuyển của điện tích.', 'Đêm khai mạc cho vở diễn mới có một sự hào hứng khác với những buổi khai mạc khác.'),
    ('0a8b12da-d377-58c8-aa9c-85bb0b2590e8', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'electronic', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ɪˌlɛkˈtɹɒn.ɪk/', 'audio/electronic.mp3', ': Of or pertaining to an electron or electrons.', 'electronic music', 'Technology & Media', 'điện tử', 'Thuộc về hoặc liên quan đến một electron hoặc các electron.', 'nhạc điện tử'),
    ('eef88084-4249-56c6-abc9-aa0fa7b3129f', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'engine', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/end͡ʒən/', 'audio/engine.mp3', 'A large construction used in warfare, such as a battering ram, catapult etc.', 'a graphics engine', 'Technology & Media', 'động cơ', 'Một công trình lớn được sử dụng trong chiến tranh, chẳng hạn như máy phá thành, máy bắn đá, v.v.', 'một động cơ đồ họa'),
    ('53a31820-5986-5029-ab5d-04e2398c3d72', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'enter', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ˈɛntə(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/enter-uk.mp3', 'The "Enter" key on a computer keyboard.', 'You should knock before you enter, unless you want to see me naked.', 'Technology & Media', 'nhập', 'Phím "Enter" trên bàn phím máy tính.', 'Bạn nên gõ cửa trước khi vào, trừ khi bạn muốn thấy tôi khỏa thân.'),
    ('70a02595-3801-5f87-ad6b-4867619a266d', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'error', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈɛɹə(ɹ)/', 'audio/error.mp3', 'The state, quality, or condition of being wrong.', 'Remove that line of code and the script should stop erroring there.', 'Technology & Media', 'lỗi', 'Trạng thái, chất lượng, hoặc điều kiện của việc sai sót.', 'Xóa dòng mã đó và tập lệnh sẽ ngừng báo lỗi ở đó.'),
    ('3f39bfee-2527-5522-bc7b-aa17884c6c2f', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'image', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈɪmɪd͡ʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/image-us.mp3', 'An optical or other representation of a real object; a graphic; a picture.', 'The Bible forbids the worship of graven images.', 'Technology & Media', 'hình ảnh', 'Một biểu diễn quang học hoặc khác của một vật thể thực; một đồ họa; một bức tranh.', 'Kinh Thánh cấm thờ phượng các hình tượng được tạc.'),
    ('1f5681ab-fa1f-5976-8501-0ae21e86e2df', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'link', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/lɪŋk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/link-us.mp3', 'Some text or a graphic in an electronic document that can be activated to display another document or trigger an action.', 'Click the hyperlink to go to the next page.', 'Technology & Media', 'liên kết', 'Một đoạn văn bản hoặc hình ảnh trong tài liệu điện tử có thể được kích hoạt để hiển thị tài liệu khác hoặc kích hoạt một hành động.', 'Nhấp vào siêu liên kết để chuyển đến trang tiếp theo.'),
    ('e70cd784-b934-5b12-ac1b-5dd7407e3b63', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'mail', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/meɪ̯l/', 'audio/mail.mp3', 'A bag or wallet.', 'Don''t forget to pick up the mail on your way.', 'Technology & Media', 'thư từ, gửi thư', 'Một túi hoặc ví.', 'Đừng quên lấy thư trên đường đi.'),
    ('0b1e6c73-5230-5ed6-ae95-0be2f86ecd1a', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'mobile', 'A2', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "A2"}, {"pos": "n", "level": "A2"}]'::jsonb, '/ˈməʊbaɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/mobile-uk.mp3', 'A kinetic sculpture or decorative arrangement made of items hanging so that they can move independently from each other.', 'there are many business opportunities in mobile', 'Technology & Media', 'di động, điện thoại', 'Một tác phẩm điêu khắc động học hoặc sắp đặt trang trí làm từ các vật treo để chúng có thể di chuyển độc lập với nhau.', 'có nhiều cơ hội kinh doanh trong lĩnh vực di động'),
    ('795acb56-b1e6-5b8f-8a86-f726a70ff3c1', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'network', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/nɛtwɜːk/', 'audio/network.mp3', 'A fabric or structure of fibrous elements attached to each other at regular intervals.', 'A network of roads crisscrossed the country.', 'Technology & Media', 'mạng lưới', 'Một cấu trúc hoặc mạng lưới của các phần tử sợi được gắn vào nhau ở những khoảng đều đặn.', 'Một mạng lưới đường bộ chằng chịt khắp đất nước.'),
    ('254a3e5a-a435-56ec-904c-6ff602b528a5', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'print', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/pɹɪnt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/print-us.mp3', 'Books and other material created by printing presses, considered collectively or as a medium.', 'TV and the internet haven''t killed print.', 'Technology & Media', 'in ấn', 'Sách và các tài liệu khác được tạo ra bởi máy in, được xem xét chung hoặc như một phương tiện.', 'TV và internet đã không giết chết in ấn.'),
    ('c6cd76fb-d904-50a7-8ead-5d28378085d2', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'program', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ˈpɹoʊˌɡɹæm/', 'audio/program.mp3', 'A set of structured activities.', 'Our program for today’s exercise class includes swimming and jogging.', 'Technology & Media', 'chương trình', 'Một tập hợp các hoạt động có cấu trúc.', 'Chương trình của lớp thể dục hôm nay của chúng tôi bao gồm bơi lội và chạy bộ.'),
    ('439c526f-0292-56b4-b78a-c875bb3cf00e', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'react', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ɹiːˈækt/', 'audio/react.mp3', 'An emoji used to express a reaction to a post on social media.', 'Sad reacts only', 'Technology & Media', 'phản ứng', 'Một biểu tượng cảm xúc dùng để thể hiện phản ứng với một bài đăng trên mạng xã hội.', 'Chỉ biểu tượng cảm xúc buồn thôi'),
    ('4b685c2d-a1e4-5929-abc2-90de8e59e8b8', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'reception', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɹɪˈsɛp.ʃn̩/', 'https://api.dictionaryapi.dev/media/pronunciations/en/reception-us.mp3', 'The act of receiving.', 'The new system provides exceptional quality of the reception signal.', 'Technology & Media', 'sự tiếp nhận', 'Hành động nhận.', 'Hệ thống mới cung cấp chất lượng tín hiệu tiếp nhận đặc biệt.'),
    ('b98b53bc-08af-52b6-83e4-e5a9f9449a58', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'record', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/ˈɹɛkɔːd/', 'audio/record.mp3', 'A disk, usually made of a polymer, used to record sound for playback on a phonograph.', 'The person had a record of the interview so she could review her notes.', 'Technology & Media', 'ghi âm, bản ghi', 'Một đĩa, thường làm bằng polymer, được sử dụng để ghi âm thanh để phát lại trên máy hát.', 'Người đó có một bản ghi cuộc phỏng vấn để cô ấy có thể xem lại ghi chú của mình.'),
    ('36919528-fb81-50fe-94ae-5427c8b9c3a3', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'reporter', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɹɪˈpɔːtə/', 'audio/reporter.mp3', 'Someone or something that reports.', 'The reporters of important security bugs may be paid a bounty by the software developer.', 'Technology & Media', 'phóng viên', 'Người nào đó hoặc thứ gì đó báo cáo.', 'Những người báo cáo lỗi bảo mật quan trọng có thể được nhà phát triển phần mềm trả thưởng.'),
    ('e5f51716-ee74-5c1b-866e-82ecb073e457', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'screen', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/skɹiːn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/screen-au.mp3', 'A physical divider intended to block an area from view, or provide shelter from something dangerous.', 'a fire screen', 'Technology & Media', 'màn hình', 'Một vật ngăn cách vật lý nhằm chặn tầm nhìn vào một khu vực, hoặc cung cấp nơi trú ẩn khỏi thứ gì đó nguy hiểm.', 'màn chắn lửa'),
    ('0365b60a-1157-53ef-859b-3ff12f17663b', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'search', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/sɜːt͡ʃ/', 'audio/search.mp3', 'An attempt to find something.', 'With only five minutes until we were meant to leave, the search for the keys started in earnest.', 'Technology & Media', 'tìm kiếm', 'Một nỗ lực để tìm thứ gì đó.', 'Với chỉ năm phút trước khi chúng tôi định rời đi, việc tìm kiếm chìa khóa bắt đầu một cách nghiêm túc.'),
    ('c02122ac-5a0e-5dda-8a52-2595146cebaf', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'web', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/wɛb/', 'https://api.dictionaryapi.dev/media/pronunciations/en/web-us.mp3', 'The World Wide Web.', 'Some of that content is now only available on the Web.', 'Technology & Media', 'mạng', 'Mạng lưới toàn cầu (World Wide Web).', 'Một số nội dung đó giờ chỉ có sẵn trên Mạng.'),
    ('5fbc21ad-c854-576e-b147-fc45a32bfe2b', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'wheel', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ʍiːl/', 'audio/wheel.mp3', 'A circular device capable of rotating on its axis, facilitating movement or transportation or performing labour in machines.', 'the wheel of life', 'Technology & Media', 'bánh xe', 'Một thiết bị hình tròn có khả năng xoay quanh trục của nó, tạo điều kiện cho việc di chuyển hoặc vận chuyển hoặc thực hiện lao động trong máy móc.', 'bánh xe của cuộc sống'),
    ('080c15df-269f-5d13-842b-c8d452809206', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'recording', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, NULL, 'audio/recording.mp3', 'To make a record of information.', 'I wanted to record every detail of what happened, for the benefit of future generations.', 'Technology & Media', 'sự ghi âm', 'Để tạo một bản ghi thông tin.', 'Tôi muốn ghi lại mọi chi tiết của những gì đã xảy ra, vì lợi ích của các thế hệ tương lai.'),
    ('9544ed5f-cb00-58cd-ad27-ab56370dff3d', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'app', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '[ʔæʔp̚]', 'https://api.dictionaryapi.dev/media/pronunciations/en/app-us.mp3', 'An application (program), especially a small one designed for a mobile device.', NULL, 'Technology & Media', 'ứng dụng', 'Một ứng dụng (chương trình), đặc biệt là một ứng dụng nhỏ được thiết kế cho thiết bị di động.', NULL),
    ('d405db18-1a6a-508e-98d2-6bbeac5707f7', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'data', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈdaetə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/data-au-nz.mp3', '(plural: data) A measurement of something on a scale understood by both the recorder (a person or device) and the reader (another person or device). The scale is arbitrarily defined, such as from 1 to 10 by ones, 1 to 100 by 0.1, or simply true or false, on or off, yes, no, or maybe, etc.', NULL, 'Technology & Media', 'dữ liệu', '(số nhiều: data) Một phép đo của một thứ gì đó trên một thang đo được cả người ghi (một người hoặc thiết bị) và người đọc (một người hoặc thiết bị khác) hiểu. Thang đo được định nghĩa tùy ý, chẳng hạn từ 1 đến.', NULL),
    ('0b116607-2e04-5b47-94a7-72befaba48b7', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'electrical', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ɪˈlɛktɹɪkəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/electrical-us.mp3', 'An electrical engineer.', NULL, 'Technology & Media', 'thuộc về điện', 'Một kỹ sư điện.', NULL),
    ('bfb060fd-f308-55ff-84b4-60b21d90a445', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'equipment', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɪˈkwɪpmənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/equipment-us.mp3', 'The act of equipping, or the state of being equipped, as for a voyage or expedition.', NULL, 'Technology & Media', 'thiết bị', 'Hành động trang bị, hoặc trạng thái được trang bị, như cho một chuyến đi biển hoặc thám hiểm.', NULL),
    ('7ecac88f-33b0-5212-a874-8768bc76cd7d', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'laptop', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈlæp.tɒp/', 'audio/laptop.mp3', 'A laptop computer.', NULL, 'Technology & Media', 'máy tính xách tay', 'Một máy tính xách tay.', NULL),
    ('eaf26a91-903e-57ef-8f92-8472d23f8c28', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'media', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈmiːdɪə/', 'audio/media.mp3', 'The middle layer of the wall of a blood vessel or lymph vessel which is composed of connective and muscular tissue.', NULL, 'Technology & Media', 'truyền thông', 'Lớp giữa của thành mạch máu hoặc mạch bạch huyết được cấu tạo từ mô liên kết và cơ.', NULL),
    ('beb7c6b8-685f-53dd-b70f-e7ac851028e0', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'plastic', 'A2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "adj", "level": "A2"}]'::jsonb, '/ˈplæstɪk/', 'audio/plastic.mp3', 'A synthetic, solid, hydrocarbon-based polymer, whether thermoplastic or thermosetting.', NULL, 'Technology & Media', 'nhựa', 'Một polymer tổng hợp, rắn, dựa trên hydrocarbon, dù là nhiệt dẻo hay nhiệt rắn.', NULL),
    ('9a324019-6780-56d2-896c-10c2b7a22fe3', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'printer', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈpɹɪntə(ɹ)/', 'audio/printer.mp3', 'One who makes prints.', NULL, 'Technology & Media', 'máy in', 'Người tạo ra các bản in.', NULL),
    ('e6db45e1-1cd6-50d3-a29c-c669a4515100', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'site', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/saɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/site-us.mp3', 'Sorrow, grief.', NULL, 'Technology & Media', 'trang web/địa điểm', 'Nỗi buồn, sự đau khổ.', NULL),
    ('6daf11aa-95ed-5805-9d5c-f3672e9f8437', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'smartphone', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈsmɑːtfəʊn/', 'audio/smartphone.mp3', 'A mobile phone with more advanced features and greater computing capacity than a featurephone.', NULL, 'Technology & Media', 'điện thoại thông minh', 'Một điện thoại di động có nhiều tính năng tiên tiến hơn và dung lượng tính toán lớn hơn một điện thoại phổ thông.', NULL),
    ('ab967025-cc7a-53df-807d-979ec6aa5b30', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'technology', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/tɛkˈnɒlədʒi/', 'audio/technology.mp3', 'The organization of knowledge for practical purposes.', NULL, 'Technology & Media', 'công nghệ', 'Việc tổ chức kiến thức cho mục đích thực tiễn.', NULL),
    ('c022d6f5-0458-5231-add0-5ff7ba62877e', '80634928-0c3c-5aae-adbc-adbbd23d3098', 'user', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈjuːzə/', 'audio/user.mp3', 'One who uses or makes use of something, a consumer/client or an express or implied licensee (free user) or a trespasser.', NULL, 'Technology & Media', 'người dùng', 'Người sử dụng hoặc tận dụng một cái gì đó, một người tiêu dùng/khách hàng hoặc một người được cấp phép ngầm định (người dùng miễn phí) hoặc một kẻ xâm nhập trái phép.', NULL)
