    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('1de71289-5506-51ef-a03a-ebaacaf3d1e7', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'ability', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/əˈ.bɪl.ɪ.ti/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ability-us.mp3', 'Suitableness.', 'This phone has the ability to have its software upgraded wirelessly.', 'Education & Learning', 'khả năng', 'Sự phù hợp.', 'Điện thoại này có khả năng nâng cấp phần mềm không dây.'),
    ('f969ead1-c043-5311-be01-1baf8884e3aa', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'argument', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈɑːɡjʊmənt/', 'audio/argument.mp3', 'A fact or statement used to support a proposition; a reason.', 'Parameters are like labeled fillable blanks used to define a function whereas arguments are passed to a function when calling it, filling in those blanks.', 'Education & Learning', 'lập luận', 'Một sự thật hoặc tuyên bố được sử dụng để hỗ trợ một đề xuất; một lý do.', 'Tham số giống như các ô trống có nhãn có thể điền được dùng để định nghĩa một hàm trong khi đối số được truyền cho một hàm khi gọi nó, điền vào những ô trống đó.'),
    ('9ccf6ff2-f73c-5968-bac2-02c7bb4d9054', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'attend', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/əˈtɛnd/', 'audio/attend.mp3', 'To listen to (something or someone); to pay attention to; regard; heed.', 'Secretaries attend to correspondence.', 'Education & Learning', 'tham dự, chú ý', 'Lắng nghe (điều gì đó hoặc ai đó); chú ý đến; quan tâm; để ý.', 'Thư ký xử lý thư tín.'),
    ('420d3f4a-ab9b-54ce-a2e0-9c8b498ec549', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'attention', 'A2', '["n", "exclam"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "exclam", "level": "A2"}]'::jsonb, '/əˈtɛn.ʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/attention-us.mp3', 'Mental focus.', 'Please direct your attention to the following words.', 'Education & Learning', 'sự chú ý', 'Sự tập trung tinh thần.', 'Xin hãy hướng sự chú ý của bạn vào những từ sau đây.'),
    ('7dbd33f9-29ae-54ed-b722-73a4b0692c8e', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'biology', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/baɪˈɒlədʒɪ/', 'audio/biology.mp3', 'The study of all life or living matter.', 'the biology of the whale', 'Education & Learning', 'sinh học', 'Nghiên cứu về tất cả sự sống hoặc vật chất sống.', 'sinh học của cá voi'),
    ('ed6ddb49-ee19-5b31-86c4-1bcc9b531f80', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'consider', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/kənˈsɪdə/', 'audio/consider.mp3', 'To think about seriously.', 'Consider that we’ve had three major events and the year has hardly begun.', 'Education & Learning', 'xem xét', 'Suy nghĩ một cách nghiêm túc.', 'Hãy xem xét rằng chúng ta đã có ba sự kiện lớn và năm mới chỉ vừa bắt đầu.'),
    ('e908aad7-8c0a-566b-be28-5042b6284879', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'context', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈkɒntɛkst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/context-uk.mp3', 'The surroundings, circumstances, environment, background or settings that determine, specify, or clarify the meaning of an event or other occurrence.', 'In what context did your attack on him happen? - We had a pretty tense relationship at the time, and when he insulted me I snapped.', 'Education & Learning', 'ngữ cảnh', 'Môi trường xung quanh, hoàn cảnh, nền tảng hoặc bối cảnh xác định, cụ thể hóa hoặc làm rõ ý nghĩa của một sự kiện hoặc sự việc khác.', 'Vụ anh tấn công hắn xảy ra trong ngữ cảnh nào? - Lúc đó mối quan hệ của chúng tôi khá căng thẳng, và khi hắn xúc phạm tôi, tôi đã nổi điên.'),
    ('39195219-2b9e-511c-bf1f-8e2cd29372d1', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'copy', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/ˈkɒpi/', 'audio/copy.mp3', 'The result of copying; an identical duplicate of an original.', 'Please bring me the copies of those reports.', 'Education & Learning', 'bản sao', 'Kết quả của việc sao chép; một bản sao giống hệt bản gốc.', 'Hãy mang cho tôi các bản sao của những báo cáo đó.'),
    ('64c8a613-4b70-5c5c-9a7a-24ba3995a1b7', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'degree', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/dɪˈɡɹiː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/degree-uk.mp3', 'A stage of proficiency or qualification in a course of study, now especially an award bestowed by a university or, in some countries, a college, as a certification of academic achievement. (In the United States, can include secondary schools.)', 'She has two bachelor''s degrees and is studying towards a master''s degree.', 'Education & Learning', 'bằng cấp', 'Một cấp độ thành thạo hoặc trình độ trong một khóa học, đặc biệt hiện nay là một giải thưởng được trao bởi một trường đại học hoặc, ở một số quốc gia, một trường cao đẳng, như một chứng nhận thành tích học tập.', 'Cô ấy có hai bằng cử nhân và đang học lên bằng thạc sĩ.'),
    ('005acf3e-5920-5077-90e9-c7617ef3363f', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'education', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˌɛdjʊˈkeɪʃn̩/', 'https://api.dictionaryapi.dev/media/pronunciations/en/education-uk.mp3', 'The process of imparting knowledge, skill and judgment.', '2016-06-17 AROP JOSEPH "Education is the slight hammer that breaks the yoke of ignorance, and moulds knowledge, skills, ideas, good moral values in a person be it a child, a youth or full grown adult. no matter a persons age learning never stops".', 'Education & Learning', 'giáo dục', 'Quá trình truyền đạt kiến thức, kỹ năng và sự phán đoán.', '2016-06-17 AROP JOSEPH "Giáo dục là chiếc búa nhỏ phá vỡ ách nô lệ của sự ngu dốt, và định hình kiến thức, kỹ năng, ý tưởng, giá trị đạo đức tốt trong một con người dù đó là một đứa trẻ, một thanh niên hay một người trưởng thành.'),
    ('ba826a50-6f39-538c-b57b-63d26b6b243f', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'experience', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ɪkˈspɪə.ɹɪəns/', 'https://api.dictionaryapi.dev/media/pronunciations/en/experience-uk.mp3', 'The effect upon the judgment or feelings produced by any event, whether witnessed or participated in; personal and direct impressions as contrasted with description or fancies; personal acquaintance; actual enjoyment or suffering.', 'It was an experience he would not soon forget.', 'Education & Learning', 'kinh nghiệm, trải nghiệm', 'Ảnh hưởng lên phán đoán hoặc cảm xúc được tạo ra bởi bất kỳ sự kiện nào, dù được chứng kiến hay tham gia; ấn tượng trực tiếp và cá nhân trái ngược với mô tả hoặc tưởng tượng; sự quen biết cá nhân;', 'Đó là một trải nghiệm mà anh ấy sẽ không sớm quên.'),
    ('9e2ac41e-2d7e-586f-ab52-b601ad767a2d', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'explanation', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˌɛkspləˈneɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/explanation-us.mp3', 'The act or process of explaining.', 'The explanation was long and drawn-out.', 'Education & Learning', 'lời giải thích', 'Hành động hoặc quá trình giải thích.', 'Lời giải thích dài dòng và lan man.'),
    ('a5218f6d-dc8e-54d7-8683-397f55d54852', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'fail', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/feɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fail-us.mp3', 'Poor quality; substandard workmanship.', 'The project was full of fail.', 'Education & Learning', 'thất bại', 'Chất lượng kém; chất lượng công việc dưới tiêu chuẩn.', 'Dự án đầy rẫy sự thất bại.'),
    ('4fc79844-36fe-571e-8663-26371b3bf0f7', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'focus', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "A2"}]'::jsonb, '/ˈfəʊ.kəs/', 'audio/focus.mp3', 'A point at which reflected or refracted rays of light converge.', 'The heat of sunlight at the focus of a magnifying glass can easily set dry leaves on fire.', 'Education & Learning', 'tập trung', 'Một điểm tại đó các tia sáng phản xạ hoặc khúc xạ hội tụ.', 'Nhiệt của ánh sáng mặt trời tại tiêu điểm của một kính lúp có thể dễ dàng làm cháy lá khô.'),
    ('2bfd8e4c-6b2b-5713-abf7-e2c1262587b8', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'ideal', 'A2', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "A2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/aɪˈdiː.əl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ideal-us.mp3', 'A perfect standard of beauty, intellect etc., or a standard of excellence to aim at.', 'the ideal theory or philosophy', 'Education & Learning', 'lý tưởng', 'Một tiêu chuẩn hoàn hảo về cái đẹp, trí tuệ, v.v., hoặc một tiêu chuẩn xuất sắc để hướng tới.', 'lý thuyết hoặc triết học lý tưởng'),
    ('0f7adcd9-b72e-55f2-9693-7f62163203d7', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'instruction', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɪnˈstɹʌkʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/instruction-us.mp3', 'The act of instructing, teaching, or furnishing with information or knowledge.', 'Instruction will be provided on how to handle difficult customers.', 'Education & Learning', 'sự hướng dẫn', 'Hành động hướng dẫn, dạy dỗ, hoặc cung cấp thông tin hoặc kiến thức.', 'Sẽ có hướng dẫn về cách xử lý khách hàng khó tính.'),
    ('ccad68da-dcf4-5a37-95f7-5b073d7f4f5b', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'knowledge', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈnɒlɪdʒ/', 'audio/knowledge.mp3', 'The fact of knowing about something; general understanding or familiarity with a subject, place, situation etc.', 'His knowledge of Iceland was limited to what he''d seen on the Travel Channel.', 'Education & Learning', 'kiến thức', 'Việc biết về điều gì đó; sự hiểu biết chung hoặc quen thuộc với một chủ đề, địa điểm, tình huống, v.v.', 'Kiến thức của anh ấy về Iceland chỉ giới hạn trong những gì anh ấy đã xem trên kênh Travel Channel.'),
    ('33ec35ff-4370-5d1e-9588-f08d290642f9', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'learning', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈlɜːnɪŋ/', 'audio/learning.mp3', 'To acquire, or attempt to acquire knowledge or an ability to do something.', 'learn from one''s mistakes', 'Education & Learning', 'việc học, kiến thức', 'Để tiếp thu, hoặc cố gắng tiếp thu kiến thức hoặc khả năng làm một việc gì đó.', 'học từ sai lầm của mình'),
    ('cb19e8b9-5717-531d-9e39-65c3c8b5df14', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'lecture', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/ˈlɛk.t͡ʃə/', 'audio/lecture.mp3', 'A spoken lesson or exposition, usually delivered to a group.', 'During class today the professor delivered an interesting lecture.', 'Education & Learning', 'bài giảng, thuyết trình', 'Một bài học hoặc trình bày bằng lời nói, thường được truyền đạt cho một nhóm.', 'Trong giờ học hôm nay, giáo sư đã trình bày một bài giảng thú vị.'),
    ('545d14c6-6a43-5d4b-95f9-0c6cfc12888a', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'mark', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "A2"}]'::jsonb, '/mɑɹk/', 'audio/mark.mp3', '(heading) Boundary, land within a boundary.', 'to mark a box or bale of merchandise', 'Education & Learning', 'đánh dấu, điểm số', '(tiêu đề) Ranh giới, đất đai trong một ranh giới.', 'để đánh dấu một hộp hoặc kiện hàng hóa'),
    ('f29b9ceb-6eee-5ed1-832f-24c540ded259', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'mathematics', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/mæθ(ə)ˈmætɪks/', 'https://api.dictionaryapi.dev/media/pronunciations/en/mathematics-us.mp3', 'An abstract representational system used in the study of numbers, shapes, structure, change and the relationships between these concepts.', 'My mathematics is always improving.', 'Education & Learning', 'toán học', 'Một hệ thống biểu diễn trừu tượng được sử dụng trong nghiên cứu về số, hình dạng, cấu trúc, sự thay đổi và mối quan hệ giữa các khái niệm này.', 'Môn toán của tôi luôn được cải thiện.'),
    ('10a0937a-5dff-5bda-a418-66ca580dd58f', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'maths', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/mæθs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/maths-uk.mp3', 'An abstract representational system used in the study of numbers, shapes, structure, change and the relationships between these concepts.', 'My mathematics is always improving.', 'Education & Learning', 'toán học', 'Một hệ thống biểu diễn trừu tượng được sử dụng trong nghiên cứu về số, hình dạng, cấu trúc, sự thay đổi và mối quan hệ giữa các khái niệm này.', 'Môn toán của tôi luôn được cải thiện.'),
    ('4ecedc7f-19c4-552b-bd77-74310dcb0596', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'method', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈmɛθəd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/method-us.mp3', 'A process by which a task is completed; a way of doing something (followed by the adposition of, to or for before the purpose of the process):', 'If one method doesn''t work, you should ask a friend to help you.', 'Education & Learning', 'phương pháp', 'Một quy trình để hoàn thành một nhiệm vụ; một cách làm điều gì đó (theo sau bởi giới từ of, to hoặc for trước mục đích của quy trình):', 'Nếu một phương pháp không hiệu quả, bạn nên nhờ bạn bè giúp đỡ.'),
    ('98a3d2e6-b1ed-52f7-a4a3-92b5a02e8f37', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'notice', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "A2"}]'::jsonb, '/ˈnəʊtɪs/', 'audio/notice.mp3', 'The act of observing; perception.', 'He took no notice of the changes, and went on as though nothing had happened.', 'Education & Learning', 'để ý, thông báo', 'Hành động quan sát; sự nhận thức.', 'Anh ấy không để ý đến những thay đổi, và cứ tiếp tục như thể không có gì xảy ra.'),
    ('e4e912b6-9a91-5d2d-9406-b303cbe1205b', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'progress', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈpɹɒɡɹɛs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/progress-1-uk.mp3', 'Movement or advancement through a series of events, or points in time; development through time.', 'Testing for the new antidote is currently in progress.', 'Education & Learning', 'tiến bộ', 'Sự di chuyển hoặc tiến triển qua một loạt sự kiện, hoặc các điểm trong thời gian; sự phát triển theo thời gian.', 'Việc thử nghiệm thuốc giải độc mới hiện đang được tiến hành.'),
    ('cc806047-6c28-5f70-8099-eea3971f7d3e', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'recommend', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ɹɛkəˈmɛnd/', 'audio/recommend.mp3', 'To bestow commendation on; to represent favourably; to suggest, endorse or encourage as an appropriate choice.', 'The board recommends Philips, given his ample experience in similar positions.', 'Education & Learning', 'đề xuất', 'Trao lời khen ngợi; đại diện một cách thuận lợi; đề xuất, tán thành hoặc khuyến khích như một lựa chọn phù hợp.', 'Hội đồng đề xuất Philips, với kinh nghiệm dồi dào của anh ấy ở các vị trí tương tự.'),
    ('a6368489-a024-53c5-9d87-96839f44db10', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'review', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/ɹɪˈvjuː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/review-us.mp3', 'A second or subsequent reading of a text or artifact in an attempt to gain new insights.', 'I need to make a review of the book before I can understand it.', 'Education & Learning', 'ôn tập', 'Việc đọc lại lần thứ hai hoặc tiếp theo một văn bản hoặc tác phẩm để cố gắng đạt được những hiểu biết mới.', 'Tôi cần ôn tập lại cuốn sách trước khi có thể hiểu nó.'),
    ('b5413180-f8a6-5b3f-b942-b81509c98566', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'source', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/sɔːs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/source-uk.mp3', 'The person, place or thing from which something (information, goods, etc.) comes or is acquired.', 'The accused refused to reveal the source of the illegal drugs she was selling.', 'Education & Learning', 'nguồn', 'Người, địa điểm hoặc vật mà từ đó một thứ gì đó (thông tin, hàng hóa, v.v.) đến hoặc được thu nhận.', 'Bị cáo từ chối tiết lộ nguồn cung cấp ma túy bất hợp pháp mà cô ta đang bán.'),
    ('84f126cd-afcd-5a83-a786-8915026c3ebf', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'teaching', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈtiːtʃɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/teaching-us.mp3', 'Something taught by a religious or philosophical authority.', 'Many follow the teachings of Confucius.', 'Education & Learning', 'sự giảng dạy, giáo lý', 'Điều gì đó được dạy bởi một thẩm quyền tôn giáo hoặc triết học.', 'Nhiều người theo giáo lý của Khổng Tử.'),
    ('1c7464e1-2fac-5fc2-9c3a-87fa442fd35b', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'thinking', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈθɪŋkɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/thinking-us.mp3', 'Thought; gerund of think.', 'What is your thinking on this subject?', 'Education & Learning', 'tư duy, suy nghĩ', 'Suy nghĩ; danh động từ của ''think''.', 'Suy nghĩ của anh về chủ đề này là gì?'),
    ('208b3f12-2125-5f28-aa8b-83f3fa726760', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'training', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈtɹeɪnɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/training-us.mp3', 'To practice an ability.', 'She trained seven hours a day to prepare for the Olympics.', 'Education & Learning', 'đào tạo, huấn luyện', 'Thực hành một kỹ năng.', 'Cô ấy đã tập luyện bảy giờ một ngày để chuẩn bị cho Thế vận hội.'),
    ('d98ee4d8-9d4f-5b2e-9e85-3fb778db55f2', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'understanding', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ʌndəˈstandɪŋ/', 'audio/understanding.mp3', 'To grasp a concept fully and thoroughly, especially (of words, statements, art, etc.) to be aware of the meaning of and (of people) to be aware of the intent of.', 'I''m sorry. I don''t understand.', 'Education & Learning', 'sự hiểu biết', 'Nắm bắt một khái niệm một cách đầy đủ và toàn diện, đặc biệt (về từ ngữ, câu nói, nghệ thuật, v.v.) là nhận thức được ý nghĩa và (về con người) là nhận thức được ý định.', 'Tôi xin lỗi. Tôi không hiểu.'),
    ('819b9ba0-b663-5556-9db0-7ed392f6ecce', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'correctly', 'A2', '["adv"]'::jsonb, '[{"pos": "adv", "level": "A2"}]'::jsonb, '/kəˈɹɛktli/', 'audio/correctly.mp3', 'In a correct manner.', NULL, 'Education & Learning', 'một cách chính xác', 'Một cách chính xác.', NULL),
    ('173b774c-17d7-5942-90cb-6b80ff3a091f', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'essay', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈɛˌseɪ/', 'audio/essay.mp3', '(authorship) A written composition of moderate length, exploring a particular issue or subject.', NULL, 'Education & Learning', 'bài luận', '(tác giả) Một bài viết có độ dài vừa phải, khám phá một vấn đề hoặc chủ đề cụ thể.', NULL),
    ('451fff6f-d983-5702-b0b1-3f0cd87c406b', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'professor', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/pɹəˈfɛsə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/professor-uk.mp3', 'The most senior rank for an academic at a university or similar institution, informally also known as "full professor." Abbreviated Prof.', NULL, 'Education & Learning', 'giáo sư', 'Cấp bậc cao cấp nhất cho một học giả tại một trường đại học hoặc tổ chức tương tự, không chính thức còn được gọi là ''giáo sư chính thức''. Viết tắt Prof.', NULL),
    ('fa02dbb5-6d2b-5c22-bd2f-e64b04057316', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'refer', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ɹɪˈfɜː/', 'audio/refer.mp3', 'To direct the attention of.', NULL, 'Education & Learning', 'tham khảo', 'Để hướng sự chú ý của.', NULL),
    ('2cb42d01-5366-565f-9623-ae36e39dfe71', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'solve', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/sɒlv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/solve-uk.mp3', '(chiefly law enforcement) A solution; an explanation.', NULL, 'Education & Learning', 'giải quyết', '(chủ yếu trong thực thi pháp luật) Một giải pháp; một lời giải thích.', NULL),
    ('97925098-e08f-5102-87a4-4f85c472ce29', '92981a0c-a0c5-56c4-a1a1-f2eff3f8e384', 'instructor', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, NULL, 'audio/instructor.mp3', 'One who instructs; a teacher.', NULL, 'Education & Learning', 'người hướng dẫn', 'Người hướng dẫn; một giáo viên.', NULL)
