INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('9ba81c25-2399-5a7f-abc8-fb9d0ef301fd', '54901bc6-8219-571b-85dd-87b6a3835707', 'cloud', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/klaʊd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cloud-uk.mp3', 'A rock; boulder; a hill.', 'He opened the door and was greeted by a cloud of bats.', 'Nature & Environment', 'đám mây', 'Một tảng đá; đá tảng; một ngọn đồi.', 'Anh ấy mở cửa và được chào đón bởi một đám mây dơi.'),
    ('57273834-f85c-502b-98f3-e50b04d2caf3', '54901bc6-8219-571b-85dd-87b6a3835707', 'coast', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/kəʊst/', 'audio/coast.mp3', 'The edge of the land where it meets an ocean, sea, gulf, bay, or large lake.', 'The rocky coast of Maine has few beaches.', 'Nature & Environment', 'bờ biển', 'Rìa của đất liền nơi nó gặp đại dương, biển, vịnh, vũng, hoặc hồ lớn.', 'Bờ biển đá của Maine có rất ít bãi biển.'),
    ('cc82c3f5-c9ca-511c-8a8f-aab4ad65eaa0', '54901bc6-8219-571b-85dd-87b6a3835707', 'deep', 'A2', '["adj", "adv"]'::jsonb, '[{"pos": "adj", "level": "A2"}, {"pos": "adv", "level": "B1"}]'::jsonb, '/diːp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/deep-au.mp3', '(with "the") The deep part of a lake, sea, etc.', 'creatures of the deep', 'Nature & Environment', 'sâu', '(với "the") Phần sâu của hồ, biển, v.v.', 'sinh vật của vùng biển sâu'),
    ('2e48c891-f8af-56db-8c98-151eca2334d2', '54901bc6-8219-571b-85dd-87b6a3835707', 'earth', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɜːθ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/earth-uk.mp3', 'The third planet of the Solar System; the world upon which humans live.', 'This is good earth for growing potatoes.', 'Nature & Environment', 'trái đất, đất', 'Hành tinh thứ ba của Hệ Mặt Trời; thế giới nơi con người sinh sống.', 'Đây là loại đất tốt để trồng khoai tây.'),
    ('bd2b4493-e474-593e-b9ed-644da299bdf4', '54901bc6-8219-571b-85dd-87b6a3835707', 'environment', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/-mɪnt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/environment-uk.mp3', 'The surroundings of, and influences on, a particular item of interest.', 'That program uses the Microsoft Windows environment.', 'Nature & Environment', 'môi trường', 'Môi trường xung quanh và những ảnh hưởng lên một đối tượng quan tâm cụ thể.', 'Chương trình đó sử dụng môi trường Microsoft Windows.'),
    ('5b2055aa-ee12-5e70-9c8a-dc7ca03cebe7', '54901bc6-8219-571b-85dd-87b6a3835707', 'field', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/fiːld/', 'audio/field.mp3', 'A land area free of woodland, cities, and towns; open country.', 'There are several species of wild flowers growing in this field.', 'Nature & Environment', 'cánh đồng, lĩnh vực', 'Một khu vực đất không có rừng, thành phố và thị trấn; vùng nông thôn mở.', 'Có một số loài hoa dại mọc trên cánh đồng này.'),
    ('a187f07e-8fb2-5f27-b66e-2985ee6eaa78', '54901bc6-8219-571b-85dd-87b6a3835707', 'forest', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈfɒɹɪst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/forest-uk.mp3', 'A dense uncultivated tract of trees and undergrowth, larger than woods.', 'a forest of criticism', 'Nature & Environment', 'rừng', 'Một khu vực rậm rạp không được canh tác với cây cối và cây bụi, lớn hơn rừng.', 'một rừng chỉ trích'),
    ('a9a537bb-55b2-544f-8a21-c5db94f868b2', '54901bc6-8219-571b-85dd-87b6a3835707', 'grass', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '[ɡɹ̠äːs]', 'audio/grass.mp3', 'Any plant of the family Poaceae, characterized by leaves that arise from nodes in the stem and leaf bases that wrap around the stem, especially those grown as ground cover rather than for grain.', 'What just happened must remain secret. Don''t be a ''grass.', 'Nature & Environment', 'cỏ', 'Bất kỳ loài thực vật nào thuộc họ Poaceae, đặc trưng bởi lá mọc từ các mấu trên thân và phần gốc lá bao quanh thân, đặc biệt là những loài được trồng làm lớp phủ mặt đất hơn là để lấy hạt.', 'Chuyện vừa xảy ra phải được giữ bí mật. Đừng có làm kẻ chỉ điểm.'),
    ('0eb9a391-1807-5a8e-8f22-e48122c5907f', '54901bc6-8219-571b-85dd-87b6a3835707', 'ground', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɡɹaʊnd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ground-au.mp3', 'The surface of the Earth, as opposed to the sky or water or underground.', 'Look, I found a ten dollar bill on the ground!', 'Nature & Environment', 'mặt đất', 'Bề mặt của Trái Đất, trái ngược với bầu trời hoặc nước hoặc dưới lòng đất.', 'Nhìn này, tôi tìm thấy một tờ mười đô la trên mặt đất!'),
    ('aa4ce56a-9141-50b0-a1df-a301278ec44d', '54901bc6-8219-571b-85dd-87b6a3835707', 'hill', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/hɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/hill-us.mp3', 'An elevated location smaller than a mountain.', 'The park is sheltered from the wind by a hill to the east.', 'Nature & Environment', 'đồi', 'Một vị trí cao nhỏ hơn một ngọn núi.', 'Công viên được che chắn khỏi gió bởi một ngọn đồi ở phía đông.'),
    ('06d1df6f-9a28-5bf1-a356-ee03019fde32', '54901bc6-8219-571b-85dd-87b6a3835707', 'insect', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈɪnsɛkt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/insect-us.mp3', 'An arthropod in the class Insecta, characterized by six legs, up to four wings, and a chitinous exoskeleton.', 'Our shed has several insect infestions, including ants, yellowjackets, and wasps.', 'Nature & Environment', 'côn trùng', 'Một loài động vật chân đốt thuộc lớp Insecta, đặc trưng bởi sáu chân, tối đa bốn cánh và bộ xương ngoài bằng kitin.', 'Nhà kho của chúng tôi có vài đám côn trùng xâm nhập, bao gồm kiến, ong bắp cày và ong vò vẽ.'),
    ('e35a1ecb-6b89-5adb-9d4a-ecf573b68614', '54901bc6-8219-571b-85dd-87b6a3835707', 'monkey', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈmʌŋki/', 'https://api.dictionaryapi.dev/media/pronunciations/en/monkey-us.mp3', 'Any member of the clade Simiiformes not also of the clade Hominoidea containing humans and apes, from which they are usually, but not universally, distinguished by smaller size, a tail, and cheek pouches.', 'He had been visiting an area zoo when a monkey swung from its tree perch, swiped his glasses and hurled them into a hippo hole.', 'Nature & Environment', 'con khỉ', 'Bất kỳ thành viên nào của nhánh Simiiformes không thuộc nhánh Hominoidea chứa con người và vượn, từ đó chúng thường, nhưng không phổ biến, được phân biệt bởi kích thước nhỏ hơn, có đuôi và có túi má.', 'Anh ấy đang thăm một vườn thú thì một con khỉ đu từ chỗ ngồi trên cây, vớ lấy cặp kính của anh và ném chúng vào hố hà mã.'),
    ('4db13572-f160-5c82-8675-25ddd8657f45', '54901bc6-8219-571b-85dd-87b6a3835707', 'moon', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/muːn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/moon-uk.mp3', 'The Earth''s moon Luna; the sole natural satellite of the Earth, represented in astronomy and astrology by ☾.', 'That''s no moon, you idiot... it''s a space station!', 'Nature & Environment', 'mặt trăng', 'Mặt trăng của Trái đất Luna; vệ tinh tự nhiên duy nhất của Trái đất, được biểu thị trong thiên văn học và chiêm tinh bằng ☾.', 'Đó không phải mặt trăng, đồ ngốc... đó là một trạm không gian!'),
    ('8531510f-2ff2-57aa-be9e-4e42a45a4726', '54901bc6-8219-571b-85dd-87b6a3835707', 'nature', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈnæɪ̯tʃə/', 'audio/nature.mp3', 'The natural world; that which consists of all things unaffected by or predating human technology, production, and design. (Compare ecosystem.)', 'Nature never lies (i.e. tells untruths).', 'Nature & Environment', 'thiên nhiên', 'Thế giới tự nhiên; bao gồm tất cả những thứ không bị ảnh hưởng bởi hoặc có trước công nghệ, sản xuất và thiết kế của con người. (So sánh với hệ sinh thái.)', 'Thiên nhiên không bao giờ nói dối.'),
    ('1294f888-52a4-5ad7-94ab-5d02095d4286', '54901bc6-8219-571b-85dd-87b6a3835707', 'ocean', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈəʊ.ʃən/', 'audio/ocean.mp3', 'One of the large bodies of water separating the continents.', 'The island is surrounded by ocean', 'Nature & Environment', 'đại dương', 'Một trong những vùng nước lớn ngăn cách các lục địa.', 'Hòn đảo được bao quanh bởi đại dương'),
    ('ffb878c0-a236-56b8-8e0c-591416414f14', '54901bc6-8219-571b-85dd-87b6a3835707', 'recycle', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ɹiˈsaɪkəl/', 'audio/recycle.mp3', 'An act of recycling.', 'Both paper and plastic can be recycled.', 'Nature & Environment', 'tái chế', 'Một hành động tái chế.', 'Cả giấy và nhựa đều có thể được tái chế.'),
    ('3a579331-bed3-5493-a943-f97f045f5e02', '54901bc6-8219-571b-85dd-87b6a3835707', 'region', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈɹiːd͡ʒn̩/', 'https://api.dictionaryapi.dev/media/pronunciations/en/region-us.mp3', 'Any considerable and connected part of a space or surface; specifically, a tract of land or sea of considerable but indefinite extent; a country; a district; in a broad sense, a place without special reference to location or extent but viewed as an entity for geographical, social or cultural reasons.', 'the equatorial regions', 'Nature & Environment', 'khu vực', 'Bất kỳ phần đáng kể và được kết nối nào của một không gian hoặc bề mặt; cụ thể, một vùng đất hoặc biển có phạm vi đáng kể nhưng không xác định; một quốc gia; một quận; theo nghĩa rộng, một nơi không có đặc điểm đặc biệt', 'các khu vực xích đạo'),
    ('6c0e3bc9-bf25-5c3a-96f5-787fd494d30c', '54901bc6-8219-571b-85dd-87b6a3835707', 'sky', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/skaɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sky-uk.mp3', 'The atmosphere above a given point, especially as visible from the ground during the day.', 'That year, a meteor fell from the sky.', 'Nature & Environment', 'bầu trời', 'Bầu khí quyển phía trên một điểm nhất định, đặc biệt là có thể nhìn thấy từ mặt đất vào ban ngày.', 'Năm đó, một thiên thạch rơi từ trên trời xuống.'),
    ('51e7fcc5-e571-5bdb-9e44-445cc7417928', '54901bc6-8219-571b-85dd-87b6a3835707', 'spider', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '[ˈspʌɪ̯ɾə(ɹ)]', 'audio/spider.mp3', 'Any of various eight-legged, predatory arthropods, of the order Araneae, most of which spin webs to catch prey.', '2002, Katharine Gasparini, Cranberry and vanilla ice cream spider, recipe in Cool Food, page 339.', 'Nature & Environment', 'con nhện', 'Bất kỳ loài động vật chân đốt ăn thịt có tám chân nào thuộc bộ Araneae, hầu hết đều giăng tơ để bắt mồi.', '2002, Katharine Gasparini, Kem nhện vani và nam việt quất, công thức trong Cool Food, trang 339.'),
    ('38a969d4-0c03-57b1-9ed3-d39d35302c1a', '54901bc6-8219-571b-85dd-87b6a3835707', 'stone', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/stɐʉn/', 'audio/stone.mp3', 'A hard earthen substance that can form large rocks.', 'a peach stone', 'Nature & Environment', 'đá, hạt', 'Một chất liệu cứng từ đất có thể tạo thành những tảng đá lớn.', 'hạt đào'),
    ('921a64e1-ae06-5ee4-9eba-0dbb509d370d', '54901bc6-8219-571b-85dd-87b6a3835707', 'wave', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B1"}]'::jsonb, '/weɪv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/wave-us.mp3', 'To move back and forth repeatedly and somewhat loosely.', 'The flag waved in the gentle breeze.', 'Nature & Environment', 'sóng', 'Di chuyển qua lại nhiều lần và hơi lỏng lẻo.', 'Lá cờ phấp phới trong làn gió nhẹ.'),
    ('f7d3db37-0c65-5459-8d2e-c3e1abd68989', '54901bc6-8219-571b-85dd-87b6a3835707', 'wild', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/waɪld/', 'https://api.dictionaryapi.dev/media/pronunciations/en/wild-us.mp3', 'The undomesticated state of a wild animal', 'After mending the lion''s leg, we returned him to the wild.', 'Nature & Environment', 'hoang dã', 'Trạng thái không được thuần hóa của một động vật hoang dã', 'Sau khi chữa lành chân cho con sư tử, chúng tôi đã trả nó về với tự nhiên hoang dã.'),
    ('b4d49cd7-b08e-58cb-864d-be6e31e9ea86', '54901bc6-8219-571b-85dd-87b6a3835707', 'wood', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/wʊd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/wood-1-au.mp3', 'The substance making up the central part of the trunk and branches of a tree. Used as a material for construction, to manufacture various items, etc. or as fuel.', 'There was lots of wood on the beach.', 'Nature & Environment', 'gỗ', 'Chất liệu tạo nên phần trung tâm của thân và cành cây. Được sử dụng làm vật liệu xây dựng, để sản xuất các mặt hàng khác nhau, v.v. hoặc làm nhiên liệu.', 'Có rất nhiều gỗ trên bãi biển.'),
    ('d4fb8aed-cb63-5a6d-9227-1ef533724015', '54901bc6-8219-571b-85dd-87b6a3835707', 'blow', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/bləʊ/', 'audio/blow.mp3', 'A strong wind.', 'We''re having a bit of a blow this afternoon.', 'Weather & Climate', 'thổi', 'Một cơn gió mạnh.', 'Chúng ta đang có một chút gió mạnh chiều nay.'),
    ('2f5969d8-df0d-5296-aa20-2b522b0f14c5', '54901bc6-8219-571b-85dd-87b6a3835707', 'climate', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈklaɪmɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/climate-us.mp3', 'An area of the earth''s surface between two parallels of latitude.', 'Industries that require a lot of fossil fuels are unlikely to be popular in the current political climate.', 'Weather & Climate', 'khí hậu', 'Một khu vực trên bề mặt trái đất nằm giữa hai vĩ tuyến.', 'Các ngành công nghiệp đòi hỏi nhiều nhiên liệu hóa thạch khó có thể phổ biến trong bối cảnh chính trị hiện tại.'),
    ('9c3ce686-fec9-5aa2-b2eb-15f3addb6ad5', '54901bc6-8219-571b-85dd-87b6a3835707', 'dry', 'A2', '["adj", "v"]'::jsonb, '[{"pos": "adj", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/dɹaɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/dry-au.mp3', 'The process by which something is dried.', 'This towel is still damp: I think it needs another dry.', 'Weather & Climate', 'khô, làm khô', 'Quá trình mà một thứ gì đó được làm khô.', 'Khăn này vẫn còn ẩm: Tôi nghĩ nó cần phải khô thêm một lần nữa.'),
    ('50496114-fc97-5d62-89ab-f21063d57046', '54901bc6-8219-571b-85dd-87b6a3835707', 'heat', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/hit/', 'https://api.dictionaryapi.dev/media/pronunciations/en/heat-us.mp3', 'Thermal energy.', 'This furnace puts out 5000 BTUs of heat. That engine is really throwing off some heat. Removal of heat from the liquid caused it to turn into a solid.', 'Weather & Climate', 'nhiệt', 'Năng lượng nhiệt.', 'Lò sưởi này tỏa ra 5000 BTU nhiệt. Động cơ đó thực sự đang tỏa ra một ít nhiệt. Việc loại bỏ nhiệt khỏi chất lỏng khiến nó chuyển thành chất rắn.'),
    ('9180f99f-5096-52ef-8ed1-a8f4698220db', '54901bc6-8219-571b-85dd-87b6a3835707', 'season', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈsiːzən/', 'audio/season.mp3', 'Each of the four divisions of a year: spring, summer, autumn (fall) and winter', 'mating season', 'Weather & Climate', 'mùa', 'Mỗi trong bốn phần của một năm: xuân, hạ, thu và đông.', 'mùa giao phối'),
    ('31637191-804d-5786-85f3-922826016b91', '54901bc6-8219-571b-85dd-87b6a3835707', 'storm', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/stɔːm/', 'audio/storm.mp3', 'Any disturbed state of the atmosphere, especially as affecting the earth''s surface, and strongly implying destructive or unpleasant weather.', 'The proposed reforms have led to a political storm.', 'Weather & Climate', 'cơn bão', 'Bất kỳ trạng thái nhiễu loạn nào của khí quyển, đặc biệt là ảnh hưởng đến bề mặt trái đất, và ngụ ý mạnh mẽ về thời tiết mang tính phá hủy hoặc khó chịu.', 'Các đề xuất cải cách đã dẫn đến một cơn bão chính trị.'),
    ('b1414f0c-2097-5a5b-a3cf-4cc9bde82777', '54901bc6-8219-571b-85dd-87b6a3835707', 'temperature', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈtɛmp(ə)ɹətʃə(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/temperature-us.mp3', 'A measure of cold or heat, often measurable with a thermometer.', 'The temperature in the room dropped nearly 20 degrees; it went from hot to cold.', 'Weather & Climate', 'nhiệt độ', 'Thước đo độ lạnh hoặc nóng, thường có thể đo được bằng nhiệt kế.', 'Nhiệt độ trong phòng giảm gần 20 độ; nó chuyển từ nóng sang lạnh.'),
    ('74b7adb4-7d45-56f2-8616-37e3e66bc4ce', '54901bc6-8219-571b-85dd-87b6a3835707', 'wet', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/wɛt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/wet-au.mp3', 'Liquid or moisture.', 'Don''t go out in the wet.', 'Weather & Climate', 'ướt', 'Chất lỏng hoặc độ ẩm.', 'Đừng ra ngoài khi trời ẩm ướt.'),
    ('3dddf44c-e274-55d2-aca2-3cb692322ef8', '54901bc6-8219-571b-85dd-87b6a3835707', 'continent', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈkɒntɪnənt/', 'audio/continent.mp3', 'Each of the main continuous land-masses on the earth''s surface, now generally regarded as seven in number, including their related islands, continental shelves etc.', NULL, 'Nature & Environment', 'lục địa', 'Mỗi khối đất liền chính liên tục trên bề mặt trái đất, hiện nay thường được coi là có bảy lục địa, bao gồm các đảo liên quan, thềm lục địa, v.v.', NULL),
    ('8aa24a38-23ad-5bbc-ab41-c412ccff4e48', '54901bc6-8219-571b-85dd-87b6a3835707', 'desert', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/dɪˈzɜːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/desert-1-uk.mp3', '(usually in the plural) That which is deserved or merited; a just punishment or reward', NULL, 'Nature & Environment', 'sa mạc', '(thường ở số nhiều) Điều xứng đáng hoặc đáng được; một hình phạt hoặc phần thưởng công bằng', NULL),
    ('5a24de8e-43b2-56db-a3d0-561233718523', '54901bc6-8219-571b-85dd-87b6a3835707', 'frog', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/fɹɒɡ/', 'audio/frog.mp3', 'A small tailless amphibian of the order Anura that typically hops.', NULL, 'Nature & Environment', 'con ếch', 'Một loài lưỡng cư nhỏ không đuôi thuộc bộ Anura thường nhảy.', NULL),
    ('bbd7b295-a215-54bf-8061-c1442a706f7a', '54901bc6-8219-571b-85dd-87b6a3835707', 'lake', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/leɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lake-uk.mp3', 'A small stream of running water; a channel for water; a drain.', NULL, 'Nature & Environment', 'hồ', 'Một dòng suối nhỏ chảy; một kênh dẫn nước; một cống thoát nước.', NULL),
    ('5169b4a8-b7af-5547-970f-ee23b5bfb979', '54901bc6-8219-571b-85dd-87b6a3835707', 'pollution', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/pəˈl(j)uːʃn̩/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pollution-uk.mp3', 'The desecration of something holy or sacred; defilement, profanation.', NULL, 'Nature & Environment', 'ô nhiễm', 'Sự làm ô uế thứ gì đó linh thiêng; sự làm bẩn, sự xúc phạm.', NULL),
    ('25b103f3-6f94-5c8f-849c-d91cc814f639', '54901bc6-8219-571b-85dd-87b6a3835707', 'valley', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈvæli/', 'https://api.dictionaryapi.dev/media/pronunciations/en/valley-uk.mp3', 'An elongated depression between hills or mountains, often with a river flowing through it.', NULL, 'Nature & Environment', 'thung lũng', 'Vùng trũng kéo dài giữa các đồi hoặc núi, thường có sông chảy qua.', NULL),
    ('5729ac57-1a6a-5fe0-be6c-64028abad9f8', '54901bc6-8219-571b-85dd-87b6a3835707', 'bear (animal)', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, NULL, 'audio/bear_(animal).mp3', NULL, NULL, 'Nature & Environment', 'con gấu', NULL, NULL),
    ('1e694c18-5a13-58eb-8ff8-d85dd4060ed5', '54901bc6-8219-571b-85dd-87b6a3835707', 'rock (stone)', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, NULL, 'audio/rock_(stone).mp3', NULL, NULL, 'Nature & Environment', 'đá', NULL, NULL),
    ('7b93e9eb-cb4e-58c7-a5e8-9ded9f1d8551', '54901bc6-8219-571b-85dd-87b6a3835707', 'wind1', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, NULL, 'audio/wind1.mp3', NULL, NULL, 'Weather & Climate', 'gió', NULL, NULL)
