INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('57312ff3-2fb9-50b7-aa28-5abd981a509c', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'abroad', 'A2', '["adv"]'::jsonb, '[{"pos": "adv", "level": "A2"}]'::jsonb, '/əˈbɹɔːd/', 'audio/abroad.mp3', 'Countries or lands abroad.', 'A tree spreads its branches abroad.', 'Travel & Transport', 'ở nước ngoài', 'Các quốc gia hoặc vùng đất ở nước ngoài.', 'Một cái cây vươn cành ra xa.'),
    ('0bb37c42-4875-51ee-a673-7989cba1d4bf', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'bridge', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/bɹɪd͡ʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bridge-us.mp3', 'A construction or natural feature that spans a divide.', 'With enough cable, we can bridge this gorge.', 'Travel & Transport', 'cây cầu', 'Một công trình hoặc đặc điểm tự nhiên bắc qua một khoảng cách.', 'Với đủ cáp, chúng ta có thể bắc cầu qua hẻm núi này.'),
    ('e8034208-7f4c-59d7-b1a6-b8b6401f801a', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'coach', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B1"}]'::jsonb, '/kəʊtʃ/', 'audio/coach.mp3', 'A wheeled vehicle, generally drawn by horse power.', 'John flew coach to Vienna, but first-class back home.', 'Travel & Transport', 'xe ngựa', 'Một phương tiện có bánh, thường được kéo bằng sức ngựa.', 'John bay hạng phổ thông đến Vienna, nhưng hạng nhất về nhà.'),
    ('ecff06e6-b6fa-5e78-98b9-92b922b63698', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'direction', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/d(a)ɪˈɹɛk.ʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/direction-uk.mp3', 'A theoretical line (physically or mentally) followed from a point of origin or towards a destination. May be relative (e.g. up, left, outbound, dorsal), geographical (e.g. north), rotational (e.g. clockwise), or with respect to an object or location (e.g. toward Boston).', 'Keep going in the same direction.', 'Travel & Transport', 'phương hướng', 'Một đường lý thuyết (về thể chất hoặc tinh thần) được theo từ một điểm xuất phát hoặc hướng tới một điểm đến. Có thể là tương đối (ví dụ: lên, trái, ra ngoài, lưng), địa lý (ví dụ: bắc), xoay (ví dụ: ngược chiều kim đồng hồ),', 'Tiếp tục đi theo cùng một hướng.'),
    ('9db6515c-0e53-5c0f-abc6-2bee2a02059f', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'driving', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈdɹaɪvɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/driving-us.mp3', 'To provide an impetus for motion or other physical change, to move an object by means of the provision of force thereto.', 'You drive nails into wood with a hammer.', 'Travel & Transport', 'lái xe, sự lái', 'Cung cấp động lực cho chuyển động hoặc thay đổi vật lý khác, di chuyển một vật thể bằng cách cung cấp lực cho nó.', 'Bạn đóng đinh vào gỗ bằng một cái búa.'),
    ('20f0c67b-5d36-5e8c-8eb3-ea108b1f7409', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'express', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ɛk.ˈspɹɛs/', 'audio/express.mp3', 'A mode of transportation, often a train, that travels quickly or directly.', 'I took the express into town.', 'Travel & Transport', 'tốc hành', 'Một phương thức vận chuyển, thường là tàu hỏa, di chuyển nhanh hoặc trực tiếp.', 'Tôi đã đi chuyến tàu tốc hành vào thị trấn.'),
    ('0e6d208e-5fec-5cfb-9566-29c25010525e', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'guide', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/ɡaɪd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/guide-us.mp3', 'Someone who guides, especially someone hired to show people around a place or an institution and offer information and explanation.', 'The guide led us around the museum and explained the exhibits.', 'Travel & Transport', 'hướng dẫn viên', 'Người hướng dẫn, đặc biệt là người được thuê để dẫn mọi người tham quan một địa điểm hoặc một cơ sở và cung cấp thông tin và giải thích.', 'Hướng dẫn viên dẫn chúng tôi đi quanh bảo tàng và giải thích các hiện vật.'),
    ('55fa0813-a3a9-59a5-a134-6f4326dbc925', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'lift', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "A2"}]'::jsonb, '/lɪft/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lift-au.mp3', 'An act of lifting or raising.', 'He gave me a lift to the bus station.', 'Travel & Transport', 'nâng lên, đi nhờ xe', 'Hành động nâng hoặc nhấc lên.', 'Anh ấy cho tôi đi nhờ xe đến trạm xe buýt.'),
    ('89dd0e27-6ee1-5f28-97d4-d85181259ee6', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'pack', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "B1"}]'::jsonb, '/pæk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pack-au.mp3', 'A bundle made up and prepared to be carried; especially, a bundle to be carried on the back, but also a load for an animal, a bale.', 'The horses carried the packs across the plain.', 'Travel & Transport', 'đóng gói, gói hàng', 'Một bó được làm và chuẩn bị để mang theo; đặc biệt, một bó để mang trên lưng, nhưng cũng là một tải trọng cho động vật, một kiện hàng.', 'Những con ngựa mang các gói hàng băng qua đồng bằng.'),
    ('4199835a-a8aa-532d-aada-b628b2ab3ab0', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'parking', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈpɑːkɪŋ/', 'audio/parking.mp3', 'To bring (something such as a vehicle) to a halt or store in a specified place.', 'I parked the drive heads of my hard disk before travelling with my laptop.', 'Travel & Transport', 'đỗ xe', 'Đưa (thứ gì đó như phương tiện) dừng lại hoặc cất giữ ở một nơi được chỉ định.', 'Tôi đã đỗ (park) đầu đọc của ổ cứng trước khi đi du lịch với máy tính xách tay.'),
    ('4e9d522b-d2c0-5f02-b1d3-eec055bc4fbf', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'passenger', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈpæsənd͡ʒə/', 'audio/passenger.mp3', 'One who rides or travels in a vehicle, but who does not operate it and is not a member of the crew.', 'Somebody in a team who does not do their fair share of the work.', 'Travel & Transport', 'hành khách', 'Người ngồi hoặc đi du lịch trong một phương tiện, nhưng không điều khiển nó và không phải là thành viên của phi hành đoàn.', 'Ai đó trong nhóm không làm phần việc công bằng của họ.'),
    ('0bf12634-4280-57e8-8ab4-eefe840d5bd4', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'pilot', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈpaɪlət/', 'audio/pilot.mp3', 'A person who steers a ship, a helmsman.', 'We would like to run a pilot in your facility before rolling out the program citywide.', 'Travel & Transport', 'phi công', 'Một người lái tàu, người cầm lái.', 'Chúng tôi muốn chạy một chương trình thí điểm tại cơ sở của bạn trước khi triển khai toàn thành phố.'),
    ('ae6b6940-6de2-5473-acbe-d251d1666391', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'route', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɹʉːt/', 'audio/route.mp3', 'A course or way which is traveled or passed.', 'The route was used so much that it formed a rut.', 'Travel & Transport', 'tuyến đường', 'Một lộ trình hoặc con đường được di chuyển hoặc đi qua.', 'Tuyến đường được sử dụng nhiều đến mức tạo thành một vết lún.'),
    ('d594d322-3feb-5bce-8f13-b20a09a682c0', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'sail', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "B1"}]'::jsonb, '/seɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sail-us.mp3', 'A piece of fabric attached to a boat and arranged such that it causes the wind to drive the boat along. The sail may be attached to the boat via a combination of mast, spars and ropes.', 'Take in sail: a storm is coming.', 'Travel & Transport', 'buồm', 'Một tấm vải gắn vào thuyền và được sắp xếp sao cho gió đẩy thuyền đi. Buồm có thể được gắn vào thuyền thông qua sự kết hợp của cột buồm, xà và dây thừng.', 'Hạ buồm xuống: một cơn bão sắp đến.'),
    ('5e6492e0-f5c2-5bac-b0b8-46b2f6dc3311', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'speed', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/spiːd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/speed-us.mp3', 'The state of moving quickly or the capacity for rapid motion; rapidity.', 'How does Usain Bolt run at that speed?', 'Travel & Transport', 'tốc độ', 'Trạng thái di chuyển nhanh hoặc khả năng chuyển động nhanh; sự nhanh chóng.', 'Làm thế nào mà Usain Bolt chạy với tốc độ đó?'),
    ('a2402e36-5968-5986-b088-be49453730d7', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'tour', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B1"}]'::jsonb, '/tɔː(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tour-au.mp3', 'A journey through a particular building, estate, country, etc.', 'On our last holiday to Spain we took a tour of the wine-growing regions.', 'Travel & Transport', 'chuyến tham quan', 'Một hành trình xuyên qua một tòa nhà, khu đất, quốc gia cụ thể, v.v.', 'Trong kỳ nghỉ cuối cùng của chúng tôi đến Tây Ban Nha, chúng tôi đã có một chuyến tham quan các vùng trồng nho.'),
    ('d05c4575-c2c2-59f8-b12c-64f121f1ac60', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'tourism', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/tɔːɹɪz(ə)m/', 'audio/tourism.mp3', 'The act of travelling or sightseeing, particularly away from one''s home.', 'libel tourism; suicide tourism; sex tourism', 'Travel & Transport', 'du lịch', 'Hành động đi du lịch hoặc tham quan, đặc biệt là xa nhà.', 'du lịch kiện tụng phỉ báng; du lịch tự tử; du lịch tình dục'),
    ('419ab035-b3b2-5ac6-80f2-d22b5bd24a8f', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'truck', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/tɹʌk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/truck-au.mp3', 'A small wheel or roller, specifically the wheel of a gun carriage.', 'Mexican open-bed trucks haul most of the fresh produce that comes into the United States from Mexico.', 'Travel & Transport', 'xe tải', 'Một bánh xe nhỏ hoặc con lăn, cụ thể là bánh xe của giá pháo.', 'Xe tải thùng mở của Mexico vận chuyển hầu hết sản phẩm tươi sống vào Hoa Kỳ từ Mexico.'),
    ('33db7236-c8ee-598f-acd8-000128ea8821', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'underground', 'A2', '["adj", "adv"]'::jsonb, '[{"pos": "adj", "level": "A2"}, {"pos": "adv", "level": "A2"}]'::jsonb, '/ˈʌndəɡɹaʊnd/', 'audio/underground.mp3', 'An underground railway, especially for mass transit of people in urban areas.', 'the French underground during World War II', 'Travel & Transport', 'ngầm, tàu điện ngầm', 'Đường sắt ngầm, đặc biệt cho việc vận chuyển hàng loạt người trong khu vực đô thị.', 'phong trào kháng chiến ngầm của Pháp trong Thế chiến II'),
    ('f56509db-015d-5713-ae43-53dfc39280c1', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'van', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/væn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/van-us.mp3', 'A covered vehicle used for carrying goods or people, usually roughly cuboid in shape, longer and higher than a car but smaller than a truck/lorry.', 'The van sped down the road.', 'Travel & Transport', 'xe tải nhỏ', 'Xe có mái che dùng để chở hàng hóa hoặc người, thường có hình dạng gần như hình hộp chữ nhật, dài và cao hơn ô tô nhưng nhỏ hơn xe tải.', 'Chiếc xe tải nhỏ phóng nhanh xuống đường.'),
    ('356ea8d7-3ab1-5bfe-968b-59ff9f051273', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'borrow', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ˈbɔɹoʊ/', 'audio/borrow.mp3', 'Deviation of the path of a rolling ball from a straight line; slope; slant.', 'This putt has a big left-to right borrow on it.', 'Shopping & Money', 'mượn', 'Sự lệch hướng của đường đi của một quả bóng lăn khỏi đường thẳng; độ dốc; độ nghiêng.', 'Cú putt này có độ lệch từ trái sang phải lớn.'),
    ('8e84547c-d39b-5dfa-95c2-03556bb56fbf', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'cash', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/kæʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cash-us.mp3', 'Money in the form of notes/bills and coins, as opposed to cheques/checks or electronic transactions.', 'After you bounced those checks last time, they want to be paid in cash.', 'Shopping & Money', 'tiền mặt', 'Tiền dưới dạng tiền giấy và tiền xu, trái ngược với séc hoặc giao dịch điện tử.', 'Sau khi bạn quỵt những tấm séc đó lần trước, họ muốn được thanh toán bằng tiền mặt.'),
    ('64c1f48f-d790-5376-b289-385b3fd6e529', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'collect', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/kəˈlɛkt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/collect-1-us.mp3', 'To gather together; amass.', 'Suzanne collected all the papers she had laid out.', 'Shopping & Money', 'thu thập', 'Tập hợp lại với nhau; tích lũy.', 'Suzanne thu thập tất cả các giấy tờ cô ấy đã bày ra.'),
    ('96f29899-e138-598b-ac5a-2a33d0719105', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'credit', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈkɹɛdɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/credit-us.mp3', 'Reliance on the truth of something said or done; faith; trust.', 'He arrived five minutes late, but to his credit he did work an extra ten minutes at the end of his shift.', 'Shopping & Money', 'tín dụng', 'Sự tin tưởng vào tính chân thật của điều gì đó được nói hoặc làm; niềm tin; sự tín nhiệm.', 'Anh ấy đến muộn năm phút, nhưng đáng khen là anh ấy đã làm thêm mười phút vào cuối ca làm việc.'),
    ('d7ba9db6-3387-509e-a2dc-f1ebc828231d', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'gold', 'A2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "adj", "level": "A2"}]'::jsonb, '/ɡɒʊld/', 'https://api.dictionaryapi.dev/media/pronunciations/en/gold-1-uk.mp3', 'A heavy yellow elemental metal of great value, with atomic number 79 and symbol Au.', 'France has won three golds and five silvers.', 'Shopping & Money', 'vàng', 'Một kim loại nguyên tố nặng màu vàng có giá trị lớn, với số nguyên tử 79 và ký hiệu Au.', 'Pháp đã giành được ba huy chương vàng và năm huy chương bạc.'),
    ('b7445cdd-299d-51fa-b718-84904c6b66c6', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'item', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '[ˈaɪ̯ɾm̩]', 'https://api.dictionaryapi.dev/media/pronunciations/en/item-us.mp3', 'A distinct physical object.', 'Tweezers are great for manipulating small items.', 'Shopping & Money', 'món đồ', 'Một vật thể vật lý riêng biệt.', 'Nhíp rất tốt để thao tác các món đồ nhỏ.'),
    ('11297db3-76ac-573d-8cc7-1f69c0eed1ac', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'owner', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈəʊnə/', 'audio/owner.mp3', 'One who owns something.', 'The police recovered the stolen car and returned it to its owner.', 'Shopping & Money', 'chủ sở hữu', 'Người sở hữu một thứ gì đó.', 'Cảnh sát đã tìm lại chiếc xe bị đánh cắp và trả lại cho chủ sở hữu của nó.'),
    ('fb1573bb-8c40-5d6c-aacd-378671bec66f', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'penny', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/pəni/', 'https://api.dictionaryapi.dev/media/pronunciations/en/penny-us.mp3', 'In the United Kingdom and Ireland, a copper coin worth 1/240 of a pound sterling or Irish pound before decimalisation. Abbreviation: d.', 'to turn an honest penny', 'Shopping & Money', 'đồng xu', 'Ở Vương quốc Anh và Ireland, một đồng xu bằng đồng trị giá 1/240 bảng Anh hoặc bảng Ireland trước khi thập phân hóa. Viết tắt: d.', 'kiếm tiền lương thiện'),
    ('34841719-92ba-5522-b246-cb8622ae0406', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'receive', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ɹɪˈsiːv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/receive-us.mp3', 'An operation in which data is received.', 'She received many presents for her birthday.', 'Shopping & Money', 'nhận', 'Một hoạt động trong đó dữ liệu được nhận.', 'Cô ấy nhận được nhiều quà cho sinh nhật của mình.'),
    ('675ddf78-ec4c-56db-9df7-8f046cdae752', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'stamp', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/stæmp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/stamp-uk.mp3', 'An act of stamping the foot, paw or hoof.', 'The horse gave two quick stamps and rose up on its hind legs.', 'Shopping & Money', 'tem', 'Hành động giậm chân, chân hoặc móng.', 'Con ngựa giậm chân nhanh hai cái và đứng dậy bằng hai chân sau.'),
    ('daafd57d-779c-55ed-a82a-02de9c4904c6', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'store', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B1"}]'::jsonb, '/stɔː/', 'audio/store.mp3', 'A place where items may be accumulated or routinely kept.', 'This building used to be a store for old tires.', 'Shopping & Money', 'cửa hàng, lưu trữ', 'Một nơi mà các vật phẩm có thể được tích lũy hoặc cất giữ thường xuyên.', 'Tòa nhà này từng là một kho chứa lốp xe cũ.'),
    ('695d3427-1c61-5627-b5a5-050e41efc038', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'transport', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B1"}]'::jsonb, NULL, 'audio/transport.mp3', 'An act of transporting; conveyance.', 'The transport of goods is not included in the price given on the website.', 'Travel & Transport', 'vận tải, vận chuyển', 'Hành động vận chuyển; sự chuyên chở.', 'Việc vận chuyển hàng hóa không được bao gồm trong giá đưa ra trên trang web.'),
    ('6388c328-d786-54e8-bc36-e38b8f450570', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'lorry', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈlɒɹi/', 'audio/lorry.mp3', 'A motor vehicle for transporting goods, and in some cases people; a truck.', NULL, 'Travel & Transport', 'xe tải', 'Một phương tiện cơ giới để vận chuyển hàng hóa, và trong một số trường hợp là người; một chiếc xe tải.', NULL),
    ('61e0db8e-640c-50ec-b341-a1c6b4ba68a9', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'motorcycle', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈməʊtəˌsaikəl/', 'audio/motorcycle.mp3', 'An open-seated motor vehicle with handlebars instead of a steering wheel, and having two (or sometimes three) wheels.', NULL, 'Travel & Transport', 'xe máy', 'Một phương tiện cơ giới chỗ ngồi mở với tay lái thay vì vô lăng, và có hai (hoặc đôi khi ba) bánh xe.', NULL),
    ('e3b4d74e-32a2-5040-933d-53bee83c8ee9', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'pass', 'A2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "A2"}, {"pos": "n", "level": "B1"}]'::jsonb, '[pʰäːs]', 'audio/pass.mp3', 'To change place.', NULL, 'Travel & Transport', 'đi qua, vượt qua', 'Thay đổi vị trí.', NULL),
    ('f2d75750-285e-59f7-8956-297141c6a3f1', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'petrol', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈpɛt.ɹəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/petrol-au.mp3', 'Petroleum, a fluid consisting of a mixture of refined petroleum hydrocarbons, primarily consisting of octane, commonly used as a motor fuel.', NULL, 'Travel & Transport', 'xăng', 'Dầu mỏ, một chất lỏng bao gồm hỗn hợp các hydrocarbon dầu mỏ tinh chế, chủ yếu gồm octan, thường được sử dụng làm nhiên liệu động cơ.', NULL),
    ('36ac1f0e-4996-5976-880c-78f25cd014ce', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'railway', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈɹeɪlˌweɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/railway-us.mp3', 'A transport system using rails used to move passengers or goods.', NULL, 'Travel & Transport', 'đường sắt', 'Hệ thống vận tải sử dụng đường ray để di chuyển hành khách hoặc hàng hóa.', NULL),
    ('de9842e7-7026-5a88-87ac-61db95cf7609', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'ship', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ʃɪp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ship-us.mp3', 'A water-borne vessel generally larger than a boat.', NULL, 'Travel & Transport', 'con tàu', 'Phương tiện vận chuyển đường thủy nói chung lớn hơn thuyền.', NULL),
    ('835d116c-0ed8-5c39-8469-e6fefa11470e', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'traveller', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈtɹævlə/', 'audio/traveller.mp3', 'A member of a particular nomadic ethnic minority in Ireland, the Pavee.', NULL, 'Travel & Transport', 'lữ khách, người du lịch', 'Một thành viên của một nhóm dân tộc du mục thiểu số cụ thể ở Ireland, người Pavee.', NULL),
    ('e59e55d4-11d3-51b3-b978-cb607c47320e', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'vehicle', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈvɪː(ə).kəl/', 'audio/vehicle.mp3', 'A conveyance; a device for carrying or transporting substances, objects or individuals.', NULL, 'Travel & Transport', 'phương tiện', 'Phương tiện chuyên chở; một thiết bị để mang hoặc vận chuyển chất, vật thể hoặc cá nhân.', NULL),
    ('14e3991c-31bc-5d98-b89c-f84a27304e97', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'lend', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/lɛnd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lend-us.mp3', 'The lumbar region; loin.', NULL, 'Shopping & Money', 'cho mượn', 'Vùng thắt lưng; hông.', NULL),
    ('87d71fda-6dad-5088-966c-bf661228c10e', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'sale', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/seɪl/', 'audio/sale.mp3', 'A hall.', NULL, 'Shopping & Money', 'bán', 'Một hội trường.', NULL),
    ('26fb6761-1bf2-5cac-be5e-64198c631d87', 'be82f5c9-4d7c-5116-b0f2-332d8a1e43a3', 'airline', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, NULL, 'audio/airline.mp3', 'A company that flies airplanes to transport people and goods.', NULL, 'Travel & Transport', 'hãng hàng không', 'Một công ty điều khiển máy bay để vận chuyển người và hàng hóa.', NULL)
