INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('c8fe09f8-a5b9-580c-9ad2-9c2ebbbd08b1', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'circle', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/ˈsɜɹkəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/circle-au.mp3', 'A two-dimensional geometric figure, a line, consisting of the set of all those points in a plane that are equally distant from a given point (center).', 'The set of all points (x, y) such that (x − 1)2 + y2 = r2 is a circle of radius r around the point (1, 0).', 'Science & Research', 'hình tròn, vòng tròn', 'Một hình hình học hai chiều, một đường, bao gồm tập hợp tất cả các điểm trong một mặt phẳng cách đều một điểm cho trước (tâm).', 'Tập hợp tất cả các điểm (x, y) sao cho (x−1)2 + y2 = r2 là một đường tròn bán kính r quanh điểm (1, 0).'),
    ('0c215be1-477f-53b3-a954-9aed6cd81d29', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'condition', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/kənˈdɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/condition-us.mp3', 'A logical clause or phrase that a conditional statement uses. The phrase can either be true or false.', 'Environmental protection is a condition for sustainability. What other planets might have the right conditions for life? The union had a dispute over sick time and other conditions of employment.', 'Science & Research', 'điều kiện', 'Một mệnh đề hoặc cụm từ logic mà một câu lệnh điều kiện sử dụng. Cụm từ có thể đúng hoặc sai.', 'Bảo vệ môi trường là một điều kiện cho sự bền vững. Những hành tinh khác có thể có điều kiện phù hợp cho sự sống? Công đoàn đã có tranh chấp về thời gian nghỉ ốm và các điều kiện làm việc khác.'),
    ('15b3e979-1fd4-5341-9414-b20c64dea270', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'cycle', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/ˈsaɪkəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cycle-us.mp3', 'An interval of space or time in which one set of events or phenomena is completed.', 'the cycle of the seasons, or of the year', 'Science & Research', 'chu kỳ', 'Một khoảng thời gian hoặc không gian trong đó một tập hợp các sự kiện hoặc hiện tượng được hoàn thành.', 'chu kỳ của các mùa, hoặc của năm'),
    ('71a749b6-e15d-5154-b162-7f689fc2839a', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'discover', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/dɪsˈkʊvə/', 'audio/discover.mp3', 'To find or learn something for the first time.', 'Turning the corner, I discovered a lovely little shop. I discovered that they sold widgets.', 'Science & Research', 'khám phá', 'Tìm hoặc học một điều gì đó lần đầu tiên.', 'Rẽ góc, tôi khám phá ra một cửa hàng nhỏ xinh xắn. Tôi phát hiện ra rằng họ bán các tiện ích.'),
    ('9fa834a3-a8ac-5aa3-9b63-0bb39fd2b8fb', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'discovery', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/dɪsˈkʌvəɹi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/discovery-ca.mp3', 'Something discovered.', 'This latest discovery should eventually lead to much better treatments for disease.', 'Science & Research', 'khám phá', 'Điều gì đó được khám phá.', 'Khám phá mới nhất này cuối cùng sẽ dẫn đến các phương pháp điều trị bệnh tốt hơn nhiều.'),
    ('167fe7bb-e84c-5fbd-9c20-509763fed599', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'effect', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɪˈfɛkt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/effect-uk.mp3', 'The result or outcome of a cause.', 'The effect of the hurricane was a devastated landscape.', 'Science & Research', 'hiệu ứng, ảnh hưởng', 'Kết quả hoặc hậu quả của một nguyên nhân.', 'Ảnh hưởng của cơn bão là một cảnh quan bị tàn phá.'),
    ('9c77110b-58d0-5a94-a635-e29eb1f473ef', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'factor', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈfæktə/', 'audio/factor.mp3', 'A doer, maker; a person who does things for another person or organization.', 'The factor of the trading post bought the furs.', 'Science & Research', 'nhân tố', 'Người thực hiện, người tạo ra; một người làm việc cho người khác hoặc tổ chức khác.', 'Nhân tố của trạm giao dịch đã mua các bộ lông thú.'),
    ('2b7fdab0-31e7-5a3c-87bd-c49b1f8ed2c3', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'gas', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɡæs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/gas-us.mp3', 'Matter in a state intermediate between liquid and plasma that can be contained only if it is fully surrounded by a solid (or in a bubble of liquid) (or held together by gravitational pull); it can condense into a liquid, or can (rarely) become a solid directly.', 'A lot of gas had escaped from the cylinder.', 'Science & Research', 'khí', 'Vật chất ở trạng thái trung gian giữa chất lỏng và plasma, chỉ có thể được chứa nếu được bao quanh hoàn toàn bởi chất rắn (hoặc trong một bong bóng chất lỏng) (hoặc được giữ lại bởi lực hấp dẫn); nó có thể ngưng tụ thành chất lỏng hoặc hóa rắn.', 'Rất nhiều khí đã thoát ra từ xi lanh.'),
    ('a40dad10-e524-568e-9571-16d2d459ea87', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'identify', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/aɪˈdɛn.tɪ.faɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/identify-us.mp3', 'To establish the identity of someone or something.', 'The Associated Press will not identify the suspect of the crime because he is a juvenile.', 'Science & Research', 'nhận dạng', 'Thiết lập danh tính của ai đó hoặc cái gì đó.', 'Hãng thông tấn Associated Press sẽ không tiết lộ danh tính nghi phạm của vụ án vì hắn là vị thành niên.'),
    ('691bf6e6-65b7-515b-8a27-07f8bacc0dad', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'invent', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ɪnˈvɛnt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/invent-us.mp3', 'To design a new process or mechanism.', 'After weeks of hard work, I invented a new way to alphabetize matchbooks.', 'Science & Research', 'phát minh', 'Thiết kế một quy trình hoặc cơ chế mới.', 'Sau nhiều tuần làm việc chăm chỉ, tôi đã phát minh ra một cách mới để sắp xếp các hộp diêm theo thứ tự bảng chữ cái.'),
    ('c94bb6fc-f145-51ee-a19f-2079596c10c7', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'invention', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɪnˈvɛnʃən/', 'audio/invention.mp3', 'Something invented.', 'I''m afraid there was no burglar. It was all the housekeeper''s invention.', 'Science & Research', 'phát minh', 'Một thứ được phát minh ra.', 'Tôi e rằng không có tên trộm nào cả. Tất cả đều là sự bịa đặt của người quản gia.'),
    ('ff257dae-a3c5-5232-8c2f-a2a6787026fb', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'lab', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/læb/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lab-uk.mp3', 'A laboratory.', 'I dropped my mixture while doing my lab, so I had to start over.', 'Science & Research', 'phòng thí nghiệm', 'Một phòng thí nghiệm.', 'Tôi làm rơi hỗn hợp của mình khi đang làm thí nghiệm, vì vậy tôi phải bắt đầu lại.'),
    ('666cf42a-6b25-5073-9929-029a1309b60a', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'material', 'A2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "adj", "level": "B2"}]'::jsonb, '/məˈtɪəɹɪəl/', 'audio/material.mp3', 'Matter which may be shaped or manipulated, particularly in making something.', 'Asphalt, composed of oil and sand, is a widely used material for roads.', 'Science & Research', 'vật liệu', 'Vật chất có thể được định hình hoặc thao tác, đặc biệt trong việc chế tạo một thứ gì đó.', 'Nhựa đường, bao gồm dầu và cát, là một vật liệu được sử dụng rộng rãi cho đường xá.'),
    ('9fd56596-6327-5a14-9a9f-404d9cd4b6fb', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'matter', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/ˈmætə/', 'audio/matter.mp3', 'Substance, material.', 'What''s the matter?; state matters', 'Science & Research', 'vấn đề, vật chất', 'Chất, vật liệu.', 'Có chuyện gì vậy?; vấn đề nhà nước'),
    ('6f28b53a-6eb9-5339-9021-8687a419d05d', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'metal', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈmɛtəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/metal-uk.mp3', '(heading) Chemical elements or alloys, and the mines where their ores come from.', 'We have American Airlines tickets, but it''s on British Airways metal.', 'Science & Research', 'kim loại', '(tiêu đề) Các nguyên tố hóa học hoặc hợp kim, và các mỏ nơi quặng của chúng được khai thác.', 'Chúng tôi có vé của American Airlines, nhưng nó được thực hiện trên phương tiện của British Airways.'),
    ('8c710b3f-968e-5023-b07f-97b3ca58d477', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'physics', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈfɪz.ɪks/', 'https://api.dictionaryapi.dev/media/pronunciations/en/physics-us.mp3', 'A medicine or drug, especially a cathartic or purgative.', 'Newtonian physics was extended by Einstein to explain the effects of travelling near the speed of light; quantum physics extends it to account for the behaviour of atoms.', 'Science & Research', 'vật lý', 'Một loại thuốc hoặc dược phẩm, đặc biệt là thuốc tẩy hoặc nhuận tràng.', 'Vật lý Newton được Einstein mở rộng để giải thích các hiệu ứng khi di chuyển gần tốc độ ánh sáng; vật lý lượng tử mở rộng nó để giải thích hành vi của nguyên tử.'),
    ('a23fc2a7-02d6-587a-8179-42314b926ffe', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'power', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈpaʊ.ə(ɹ)/', 'audio/power.mp3', 'Ability to do or undergo something.', 'the mechanical powers', 'Science & Research', 'năng lượng', 'Khả năng làm hoặc trải qua điều gì đó.', 'các lực cơ học'),
    ('dfe3a1b5-1fa1-546a-b163-2a32b5abbeae', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'research', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/ɹɪˈsɜːtʃ/', 'audio/research.mp3', 'Diligent inquiry or examination to seek or revise facts, principles, theories, applications, etc.; laborious or continued search after truth.', 'The research station that houses Wang and his team is outside Lijiang, a city of about 1.2 million people.', 'Science & Research', 'nghiên cứu', 'Sự tìm tòi hoặc kiểm tra cẩn thận để tìm kiếm hoặc sửa đổi sự thật, nguyên tắc, lý thuyết, ứng dụng, v.v.; sự tìm kiếm sự thật một cách công phu hoặc liên tục.', 'Trạm nghiên cứu nơi Wang và nhóm của anh ấy ở bên ngoài Lijiang, một thành phố với khoảng 1,2 triệu dân.'),
    ('2bc44fd6-b610-5c17-8441-0eee55fb1e99', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'structure', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈstɹʌktʃə(ɹ)/', 'audio/structure.mp3', 'A cohesive whole built up of distinct parts.', 'The birds had built an amazing structure out of sticks and various discarded items.', 'Science & Research', 'cấu trúc', 'Một tổng thể gắn kết được xây dựng từ các phần riêng biệt.', 'Những con chim đã xây dựng một cấu trúc tuyệt vời từ những cành cây và các vật dụng bị vứt bỏ khác nhau.'),
    ('88fca596-06dc-5b89-afa2-99befe3fa434', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'system', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈsɪstəm/', 'audio/system.mp3', 'A collection of organized things; a whole composed of relationships among its members.', 'There are eight planets in the solar system.', 'Science & Research', 'hệ thống', 'Một tập hợp các thứ được tổ chức; một tổng thể được cấu thành từ các mối quan hệ giữa các thành phần của nó.', 'Có tám hành tinh trong hệ mặt trời.'),
    ('7ebe02c5-f15f-55eb-a17a-649353541949', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'army', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈɑː.miː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/army-uk.mp3', 'A large, highly organized military force, concerned mainly with ground (rather than air or naval) operations.', 'The army was sent in to quell the uprising.', 'Law & Politics', 'quân đội', 'Một lực lượng quân sự lớn, được tổ chức cao, chủ yếu liên quan đến các hoạt động trên bộ (thay vì trên không hoặc hải quân).', 'Quân đội được cử đến để dập tắt cuộc nổi dậy.'),
    ('8821001c-99e6-522e-ab25-09b957c7bb99', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'attack', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "A2"}]'::jsonb, '/əˈtæk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/attack-au.mp3', 'An attempt to cause damage, injury to, or death of opponent or enemy.', 'They claimed the censorship of the article was an attack on free speech.', 'Law & Politics', 'tấn công', 'Một nỗ lực gây thiệt hại, thương tích hoặc tử vong cho đối thủ hoặc kẻ thù.', 'Họ tuyên bố việc kiểm duyệt bài báo là một cuộc tấn công vào quyền tự do ngôn luận.'),
    ('65cbea16-f2e9-5e72-b4ec-50eec6632aba', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'award', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B1"}]'::jsonb, '/əˈwɔːd/', 'audio/award.mp3', 'A judgment, sentence, or final decision. Specifically: The decision of arbitrators in a case submitted.', 'the arbitrators awarded damages to the complainant', 'Law & Politics', 'giải thưởng, phán quyết', 'Một phán quyết, bản án, hoặc quyết định cuối cùng. Cụ thể: Quyết định của trọng tài trong một vụ việc được đệ trình.', 'các trọng tài đã phán quyết bồi thường thiệt hại cho nguyên đơn'),
    ('e4728e02-1543-53cf-a1f2-b13324543939', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'case', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/keɪs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/case-us.mp3', 'An actual event, situation, or fact.', 'For a change, in this case, he was telling the truth.', 'Law & Politics', 'trường hợp, vụ án', 'Một sự kiện, tình huống hoặc sự thật thực tế.', 'Thay đổi một chút, trong trường hợp này, anh ta đang nói sự thật.'),
    ('aa6307fa-e946-50bc-ba40-e916f6cdbe15', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'crime', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/kɹaɪm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/crime-us.mp3', 'A specific act committed in violation of the law.', 'Crime doesn’t pay.', 'Law & Politics', 'tội phạm', 'Một hành vi cụ thể được thực hiện vi phạm pháp luật.', 'Phạm tội không có lợi.'),
    ('a865f840-aa07-5f0a-9d9e-270a877bf483', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'criminal', 'A2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "adj", "level": "B1"}]'::jsonb, '/ˈkɹɪmənəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/criminal-us.mp3', 'A person who is guilty of a crime, notably breaking the law.', 'His long criminal record suggests that he is a dangerous man.', 'Law & Politics', 'tội phạm', 'Một người phạm tội, đặc biệt là vi phạm pháp luật.', 'Lý lịch tội phạm dài của anh ta cho thấy anh ta là một người đàn ông nguy hiểm.'),
    ('be4e2531-e2f2-50bf-8412-e7ca84b3c4c4', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'evidence', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '[ˈɛvəɾəns]', 'https://api.dictionaryapi.dev/media/pronunciations/en/evidence-us.mp3', 'Facts or observations presented in support of an assertion.', 'There is no evidence that anyone was here earlier.', 'Law & Politics', 'bằng chứng', 'Sự kiện hoặc quan sát được trình bày để hỗ trợ một tuyên bố.', 'Không có bằng chứng nào cho thấy đã có ai ở đây trước đó.'),
    ('fa500b54-38e4-54b6-9622-de28f57c4b6b', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'government', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈɡʌvə(n)mənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/government-uk.mp3', 'The body with the power to make and/or enforce laws to control a country, land area, people or organization.', 'If the citizens must follow the law, then the government must follow the constitution.', 'Law & Politics', 'chính phủ', 'Cơ quan có quyền lập và/hoặc thực thi luật để kiểm soát một quốc gia, khu vực đất đai, con người hoặc tổ chức.', 'Nếu công dân phải tuân theo luật pháp, thì chính phủ phải tuân theo hiến pháp.'),
    ('609f4154-0aa7-557d-99ca-37d0c5346cc9', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'gun', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ɡʌn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/gun-1-us.mp3', 'A device for projecting a hard object very forcefully; a firearm or cannon.', 'Guns were considered improvements of crossbows and catapults.', 'Law & Politics', 'súng', 'Một thiết bị để bắn một vật thể cứng rất mạnh; một súng cầm tay hoặc đại bác.', 'Súng được coi là cải tiến của nỏ và máy bắn đá.'),
    ('fa3c7c9d-2f4c-57ff-86c9-61e57310f7d2', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'law', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/lɔː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/law-uk.mp3', 'The body of binding rules and regulations, customs and standards established in a community by its legislative and judicial authorities.', 'entrapment is against the law', 'Law & Politics', 'luật pháp', 'Tập hợp các quy tắc và quy định ràng buộc, phong tục và tiêu chuẩn được thiết lập trong một cộng đồng bởi các cơ quan lập pháp và tư pháp của nó.', 'gài bẫy là trái pháp luật'),
    ('10dd605f-1878-57b2-95b8-bbabb55fd902', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'lawyer', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈlɔɪ.ə(ɹ)/', 'audio/lawyer.mp3', 'A professional person qualified (as by a law degree or bar exam) and authorized to practice law, i.e. represent parties in lawsuits or trials and give legal advice.', 'A lawyer''s time and advice are his stock in trade. - aphorism often credited to Abraham Lincoln, but without attestation', 'Law & Politics', 'luật sư', 'Một chuyên gia có trình độ (bằng cách có bằng luật hoặc vượt qua kỳ thi luật sư) và được ủy quyền hành nghề luật, tức là đại diện cho các bên trong các vụ kiện hoặc phiên tòa và đưa ra lời khuyên pháp lý.', 'Thời gian và lời khuyên của một luật sư là vốn liếng của anh ta. - châm ngôn thường được cho là của Abraham Lincoln, nhưng không có bằng chứng xác thực'),
    ('4f200787-ea26-5fd6-98c1-4c7a01966a27', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'major', 'A2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "A2"}]'::jsonb, '/ˈmeɪ.dʒə(ɹ)/', 'audio/major.mp3', 'A military rank between captain and lieutenant colonel.', 'He used to be a major in the army.', 'Law & Politics', 'thiếu tá', 'Một cấp bậc quân sự giữa đại úy và trung tá.', 'Anh ấy từng là thiếu tá trong quân đội.'),
    ('0401a22b-4697-5a18-bd5d-e41e42cd74f2', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'permission', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/pəˈmɪʃən/', 'audio/permission.mp3', 'Authorisation; consent (especially formal consent from someone in authority)', 'Sire, do I have your permission to execute this traitor?', 'Law & Politics', 'sự cho phép', 'Sự ủy quyền; sự đồng ý (đặc biệt là sự đồng ý chính thức từ người có thẩm quyền)', 'Thưa ngài, tôi có được ngài cho phép xử tử tên phản bội này không?'),
    ('ce8234a6-fe7d-5f13-9d55-773edc9020bf', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'president', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈpɹɛzɨdənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/president-uk.mp3', 'An act in the past which may be used as an example to help decide the outcome of similar instances in the future.', 'The vast majority of presidents have been male.', 'Law & Politics', 'tổng thống', 'Một hành động trong quá khứ có thể được dùng làm ví dụ để giúp quyết định kết quả của những trường hợp tương tự trong tương lai.', 'Đại đa số các tổng thống đều là nam giới.'),
    ('ca468f1c-0029-5939-9bc6-df095bad4683', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'prison', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈpɹɪzən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/prison-us.mp3', 'A place or institution of confinement, especially of long-term confinement for those convicted of serious crimes or otherwise considered undesirable by the government.', 'The cold stone walls of the prison had stood for over a century.', 'Law & Politics', 'nhà tù', 'Một nơi hoặc tổ chức giam giữ, đặc biệt là giam giữ dài hạn cho những người bị kết án về tội nghiêm trọng hoặc bị chính phủ coi là không mong muốn.', 'Những bức tường đá lạnh lẽo của nhà tù đã tồn tại hơn một thế kỷ.'),
    ('498f9291-7c7d-5c00-903a-bc07acda4248', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'state', 'A2', '["n", "adj", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "adj", "level": "A2"}, {"pos": "v", "level": "B1"}]'::jsonb, '/steɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/state-uk.mp3', 'A condition; a set of circumstances applying at any given time.', 'He stated that he was willing to help.', 'Law & Politics', 'nhà nước', 'Một điều kiện; một tập hợp các hoàn cảnh áp dụng tại bất kỳ thời điểm nào.', 'Ông ấy tuyên bố rằng ông sẵn sàng giúp đỡ.'),
    ('4eca7f8c-b976-5ce6-9141-0b41ee0f008e', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'steal', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/stiːl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/steal-us.mp3', 'The act of stealing.', 'At this price, this car is a steal.', 'Law & Politics', 'ăn cắp', 'Hành động ăn cắp.', 'Với giá này, chiếc xe này là một món hời.'),
    ('c17ee582-be59-5472-bd00-e5005a177542', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'war', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/wɔː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/war-uk.mp3', 'Organized, large-scale, armed conflict between countries or between national, ethnic, or other sizeable groups, usually involving the engagement of military forces.', 'The war was largely between Sunni and Shia militants.', 'Law & Politics', 'chiến tranh', 'Xung đột vũ trang có tổ chức, quy mô lớn giữa các quốc gia hoặc giữa các nhóm dân tộc, sắc tộc hoặc các nhóm có quy mô đáng kể khác, thường liên quan đến sự tham gia của lực lượng quân sự.', 'Cuộc chiến chủ yếu là giữa các phần tử cực đoan Sunni và Shia.'),
    ('8c22cfad-d1cd-5907-8eeb-f8790edb22e3', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'survey', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B2"}]'::jsonb, NULL, 'audio/survey.mp3', 'The act of surveying; a general view.', 'A survey of the stores of a ship; a survey of roads and bridges; a survey of buildings.', 'Science & Research', 'khảo sát', 'Hành động khảo sát; một cái nhìn tổng quát.', 'Một cuộc khảo sát hàng hóa của tàu; một cuộc khảo sát đường xá và cầu cống; một cuộc khảo sát tòa nhà.'),
    ('18b3b6e0-446a-58fb-bd5f-c017b1182ad8', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'chemistry', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈkɛm.ɪ.stɹi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/chemistry-us.mp3', 'The branch of natural science that deals with the composition and constitution of substances and the changes that they undergo as a consequence of alterations in the constitution of their molecules.', NULL, 'Science & Research', 'hóa học', 'Ngành khoa học tự nhiên nghiên cứu về thành phần và cấu tạo của các chất và những thay đổi mà chúng trải qua do hậu quả của sự thay đổi trong cấu trúc phân tử của chúng.', NULL),
    ('62043389-641a-5b00-81cc-897852685559', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'energy', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈɛnəd͡ʒi/', 'audio/energy.mp3', 'The impetus behind all motion and all activity.', NULL, 'Science & Research', 'năng lượng', 'Động lực đằng sau mọi chuyển động và mọi hoạt động.', NULL),
    ('e80efb14-95f8-544b-ad73-0334abee6fa0', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'exist', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/ɪɡˈzɪst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/exist-us.mp3', '(stative) to be; have existence; have being or reality', NULL, 'Science & Research', 'tồn tại', '(trạng thái) là; có sự tồn tại; có thực thể hoặc hiện thực', NULL),
    ('345be30b-9a76-51c1-8364-f2044589ae6d', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'experiment', 'A2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "A2"}, {"pos": "v", "level": "B1"}]'::jsonb, '/ɛk.ˈspɛ.ɹɪ.mənt/', 'audio/experiment.mp3', 'A test under controlled conditions made to either demonstrate a known truth, examine the validity of a hypothesis, or determine the efficacy of something previously untried.', NULL, 'Science & Research', 'thí nghiệm', 'Một bài kiểm tra trong điều kiện được kiểm soát được thực hiện để chứng minh một sự thật đã biết, kiểm tra tính hợp lệ của một giả thuyết, hoặc xác định hiệu quả của một thứ gì đó chưa từng được thử trước đây.', NULL),
    ('d5c8a80a-64ed-554a-a008-62a09d98db0d', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'planet', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/ˈplænət/', 'audio/planet.mp3', 'Each of the seven major bodies which move relative to the fixed stars in the night sky—the Moon, Mercury, Venus, the Sun, Mars, Jupiter and Saturn.', NULL, 'Science & Research', 'hành tinh', 'Mỗi trong bảy thiên thể chính di chuyển so với các ngôi sao cố định trên bầu trời đêm—Mặt Trăng, Sao Thủy, Sao Kim, Mặt Trời, Sao Hỏa, Sao Mộc và Sao Thổ.', NULL),
    ('c9911d36-d736-5594-8b46-c392e9793d6f', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'predict', 'A2', '["v"]'::jsonb, '[{"pos": "v", "level": "A2"}]'::jsonb, '/pɹɪˈdɪkt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/predict-us.mp3', 'A prediction.', NULL, 'Science & Research', 'dự đoán', 'Một dự đoán.', NULL),
    ('5a865fc3-bfb3-51e2-afbb-9e5b01ea8cc3', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'solution', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/səˈl(j)uːʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/solution-us.mp3', 'A homogeneous mixture, which may be liquid, gas or solid, formed by dissolving one or more substances.', NULL, 'Science & Research', 'dung dịch', 'Một hỗn hợp đồng nhất, có thể là chất lỏng, khí hoặc rắn, được tạo thành bằng cách hòa tan một hoặc nhiều chất.', NULL),
    ('1ced4991-bab0-588a-bfff-ad00e85751fe', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'detective', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/dɪˈtɛktɪv/', 'audio/detective.mp3', '(law enforcement) A police officer who looks for evidence as part of solving a crime; an investigator.', NULL, 'Law & Politics', 'thám tử', '(thực thi pháp luật) Một sĩ quan cảnh sát tìm kiếm bằng chứng như một phần của việc giải quyết tội phạm; một nhà điều tra.', NULL),
    ('f0cf5ac2-022d-5eee-8c33-92e1ffee45ce', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'thief', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, '/θiːf/', 'audio/thief.mp3', 'One who carries out a theft.', NULL, 'Law & Politics', 'kẻ trộm', 'Người thực hiện một vụ trộm.', NULL),
    ('21208f55-38bd-5648-9e2a-9cb67f5b80c1', '8f02c7b5-dca8-5016-8ce3-51c756a27bae', 'researcher', 'A2', '["n"]'::jsonb, '[{"pos": "n", "level": "A2"}]'::jsonb, NULL, 'audio/researcher.mp3', 'One who researches.', NULL, 'Science & Research', 'nhà nghiên cứu', 'Người nghiên cứu.', NULL)
